var project = (function (exports) {
  'use strict';

  const focus_names = {
    entry: "entry",
    identifier: "identifier",
    detail: "detail",
    question: "question"
  };
  const suffixes = {
    cont: "-container"
  };
  const button_names = {
    start: "start-button",
    back: "back-button",
    submit: "form-submit"
  };
  function _get_question_input_list(containers) {
    let question_list = [];
    for (let i = 0; i < containers.question_list.length; i++) {
      let question = containers.question_list[i];
      let question_inputs = question.querySelectorAll("input,textarea");
      for (let input of question_inputs) {
        input.question_index = i;
      }
      question_list.push(Array.from(question_inputs));
    }
    return question_list;
  }
  function get_components() {
    let containers = {
      entry: document.getElementById(focus_names.entry + suffixes.cont),
      identifier: document.getElementById(focus_names.identifier + suffixes.cont),
      detail: document.getElementById(focus_names.detail + suffixes.cont),
      question_list: Array.from(document.getElementsByClassName(focus_names.question))
    };
    return {
      navbars: {
        main: document.getElementById("navbar"),
        brand: document.getElementById("top-brand")
      },
      containers: containers,
      buttons: {
        start: document.getElementById(button_names.start),
        back: document.getElementById(button_names.back),
        submit: document.getElementById(button_names.submit)
      },
      input_map: {
        identifier: Array.from(containers.identifier.querySelectorAll("input,textarea")),
        question_list: _get_question_input_list(containers)
      }
    };
  }

  class SubmitMapWidget extends MapWidget {
    constructor(options) {
      super(options);
      document.getElementById(options.map_id).style = null;
      this.map.getView().setCenter(ol.proj.transform([-70.668423, -33.447869], 'EPSG:4326', 'EPSG:3857'));
      this.interactions.modify.setActive(false);
      this.map.getView().on("change:center", event => {
        let feature = this.get_feature_marker();
        if (feature) {
          let center = this.map.getView().getCenter();
          let geometry = feature.getGeometry();
          geometry.setCoordinates(center);
          this.serializeFeatures();
        }
      });
      this.featureOverlay.setStyle(new ol.style.Style({
        image: new ol.style.Icon( /** @type {olx.style.IconOptions} */{
          color: '#8959A8',
          crossOrigin: 'anonymous',
          src: options.point_image_url
        })
      }));
    }
    get_feature_marker() {
      let features = this.featureOverlay.getSource().getFeatures();
      return features.length > 0 ? features[0] : null;
    }
    createMap() {
      return new ol.Map({
        target: this.options.map_id,
        controls: ol.control.defaults.defaults({
          attribution: false
        }),
        layers: [new ol.layer.Tile({
          source: new ol.source.OSM()
        })],
        view: new ol.View({
          zoom: this.options.default_zoom
        })
      });
    }
    dispatch_input_event() {
      document.getElementById(this.options.id).dispatchEvent(new Event("input"));
    }
    serializeFeatures() {
      super.serializeFeatures();
      let feature = this.get_feature_marker();
      let geometry = feature.getGeometry();
      this.map.getView().setCenter(geometry.getCoordinates());
      this.dispatch_input_event();
    }
    clearFeatures() {
      super.clearFeatures();
      this.dispatch_input_event();
    }
  }
  function set_point_input_event(input) {
    let map_data = input.parentElement.querySelector(".map-data");
    let options = JSON.parse(map_data.getAttribute("data"));
    input.mapwidget = new SubmitMapWidget(options);
  }
  function set_response_geolocation(manager, containers, input_map) {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(position => {
        manager.user_location = {
          lon: position.coords.longitude,
          lat: position.coords.latitude
        };
        let geolocation_input = containers.identifier.querySelector("input[name='location']");
        geolocation_input.value = `POINT(${manager.user_location.lon} ${manager.user_location.lat})`;
        for (let question_inputs of input_map.question_list) {
          for (let input of question_inputs) {
            if (input.mapwidget) {
              input.mapwidget.map.getView().setCenter(ol.proj.transform([manager.user_location.lon, manager.user_location.lat], 'EPSG:4326', 'EPSG:3857'));
            }
          }
        }
      });
    }
  }

  function _show_without_image(input) {
    let container = input.parentElement;
    container.style.backgroundImage = null;
    container.querySelector(".image-icon").classList.remove("hidden");
    container.querySelector(".image-icon-description").classList.remove("hidden");
    container.querySelector(".closed-icon").classList.add("hidden");
  }
  function _show_with_image(input, url) {
    let container = input.parentElement;
    container.style.backgroundImage = `url(${url})`;
    container.querySelector(".image-icon").classList.add("hidden");
    container.querySelector(".image-icon-description").classList.add("hidden");
    container.querySelector(".closed-icon").classList.remove("hidden");
  }
  function set_image_preview(input) {
    _show_without_image(input);
    let files = input.files;
    let reducer = new window.ImageBlobReduce({
      pica: window.ImageBlobReduce.pica({
        features: ['js', 'wasm', 'ww']
      })
    });
    if (files.length > 0) {
      let file = files[0];
      reducer.toBlob(file, {
        max: 1000
      }).then(blob => {
        let url = URL.createObjectURL(blob);
        let reduced_file = new File([blob], input.files[0].name, {
          type: "mime/type",
          lastModified: new Date().getTime()
        });
        let files_container = new DataTransfer();
        files_container.items.add(reduced_file);
        _show_with_image(input, url);
      }).catch(error => {
        console.log(error);
      });
    }
  }

  function validate_rut(input) {
    let validator = {
      val: function (rut) {
        if (!/^[0-9]+[-|‐]{1}[0-9kK]{1}$/.test(rut)) {
          return false;
        }
        let tmp = rut.split('-');
        let digv = tmp[1];
        let _rut = tmp[0];
        if (digv == 'K') {
          digv = 'k';
        }
        return validator.dv(_rut) == digv;
      },
      dv: function (T) {
        let M = 0,
          S = 1;
        for (; T; T = Math.floor(T / 10)) S = (S + T % 10 * (9 - M++ % 6)) % 11;
        return S ? S - 1 : 'k';
      }
    };
    if (!input.value || input.value && validator.val(input.value)) {
      input.setCustomValidity("");
    } else {
      let message = "Rut inválido";
      input.setCustomValidity(message);
    }
  }
  function _get_question_errors(question_index, containers) {
    let errors = containers.question_list[question_index].querySelector(".errors");
    errors.textContent = "";
    return errors;
  }
  function validate_image_question(input, report) {
    let required = input.hasAttribute("required");
    let question_container = input.parentElement.parentElement.parentElement;
    let errors = question_container.querySelector(".errors");
    let image_input_container = input.parentElement;
    errors.textContent = "";
    image_input_container.classList.remove("error");
    input.setCustomValidity("");
    if (required && input.files.length == 0) {
      let message = "*Este campo es obligatorio";
      if (report) {
        errors.textContent = message;
        image_input_container.classList.add("error");
      }
      input.value = "";
      input.setCustomValidity(message);
    }
    set_image_preview(input);
  }
  function validate_options_question(input, containers, report) {
    let field_container = containers.question_list[input.question_index].querySelector("[field='options']");
    let maxlength = parseInt(field_container.getAttribute("maxlength"));
    let required = field_container.hasAttribute("required");
    let checked_inputs = Array.from(field_container.querySelectorAll("input")).filter(input => input.checked).length;
    let errors = _get_question_errors(input.question_index, containers);
    input.setCustomValidity("");
    if (checked_inputs > maxlength && input.checked) {
      let message = `Seleccione máximo ${maxlength} respuesta${maxlength > 1 ? 's' : ''}`;
      errors.textContent = message;
      input.checked = false;
    } else if (required && checked_inputs == 0 && !input.checked) {
      let message = `Debe seleccionar al menos una opción`;
      if (report) {
        errors.textContent = message;
      }
      input.setCustomValidity(message);
    } else {
      for (let i of field_container.querySelectorAll("input")) {
        i.setCustomValidity("");
      }
    }
    if (input.checked) {
      input.parentElement.classList.add("checked");
    } else {
      input.parentElement.classList.remove("checked");
    }
  }
  function validate_point_question(input, containers, report) {
    let field_container = containers.question_list[input.question_index].querySelector("[field='point']");
    let required = field_container.hasAttribute("required");
    let errors = _get_question_errors(input.question_index, containers);
    let clear_features = input.parentElement.querySelector(".clear-features");
    field_container.classList.remove("error");
    input.setCustomValidity("");
    if (input.value) {
      clear_features.classList.remove("hidden");
    } else {
      clear_features.classList.add("hidden");
    }
    if (required && !input.value) {
      let message = "*Este campo es requerido";
      if (report) {
        field_container.classList.add("error");
        errors.textContent = message;
      }
      input.setCustomValidity(message);
    }
  }
  function validate_text_question(input, containers, report) {
    let field_container = input.parentElement;
    let required = field_container.hasAttribute("required");
    let maxlength = input.getAttribute("maxlength");
    let minlength = input.getAttribute("minlength");
    maxlength = Number.isInteger(maxlength) ? maxlength : 255;
    minlength = Number.isInteger(minlength) ? minlength : 1;
    let errors = _get_question_errors(input.question_index, containers);
    field_container.classList.remove("error");
    input.setCustomValidity("");
    let valid = true;
    let message = null;
    if (required && !input.value) {
      message = "*Este campo es requerido";
      valid = false;
    } else if (input.value && input.value.length > maxlength) {
      message = `*Este campo debe tener como máximo ${maxlength} caracteres`;
      valid = false;
    } else if (input.value && input.value.length < minlength) {
      message = `*Este campo debe tener como mínimo ${minlength} caracteres`;
      valid = false;
    }
    if (!valid) {
      if (report) {
        field_container.classList.add("error");
        errors.textContent = message;
      }
      input.setCustomValidity(message);
    }
  }
  const validator = {
    validate_rut,
    validate_image_question,
    validate_options_question,
    validate_point_question,
    validate_text_question
  };

  class QuerySubmitEngine {
    constructor({
      focus = "entry",
      auth_url = "",
      csrf_token = ""
    }) {
      this.auth_url = auth_url;
      this.csrf_token = csrf_token;
      this.closed_sk = new URLSearchParams(window.location.search).get("k");
      this.closed_email = new URLSearchParams(window.location.search).get("e");
      this.hidden_class_name = "hidden";
      this.comp = get_components();
      this._set_focus(focus);
      this._set_event_buttons();
      this._set_identifier_inputs();
      this._set_question_inputs();
      set_response_geolocation(this, this.comp.containers, this.comp.input_map);
    }
    _set_focus(focus) {
      this.focus = !isNaN(focus) ? parseInt(focus) : focus;
      this.show_view(this.focus);
    }
    _set_event_buttons() {
      this.click_start_button = this.click_start_button.bind(this);
      this.comp.buttons.start.addEventListener("click", this.click_start_button, false);
      this.click_next_button = this.click_next_button.bind(this);
      this.comp.buttons.submit.addEventListener("click", this.click_next_button, false);
      this.show_back_form = this.show_back_form.bind(this);
      this.comp.buttons.back.addEventListener("click", this.show_back_form, false);
    }
    _set_identifier_inputs() {
      this.change_identifier_input = this.change_identifier_input.bind(this);
      for (let input of this.comp.input_map.identifier) {
        if (this.closed_email && input.getAttribute("name") == "email") {
          input.value = this.closed_email;
          input.setAttribute("disabled", true);
        }
        input.addEventListener("input", this.change_identifier_input, false);
      }
    }
    _set_question_inputs() {
      this.change_question_input = this.change_question_input.bind(this);
      this.click_image_clear = this.click_image_clear.bind(this);
      for (let inputs of this.comp.input_map.question_list) {
        for (let input of inputs) {
          input.addEventListener("input", this.change_question_input, false);
          if (input.type == "checkbox") {
            validator.validate_options_question(input, this.comp.containers, false);
          }
          if (input.classList.contains("vSerializedField")) {
            set_point_input_event(input);
            validator.validate_point_question(input, this.comp.containers, false);
          }
          if (input.type == "file") {
            let input_container = input.parentElement;
            let input_close_icon = input_container.querySelector(".closed-icon");
            input_close_icon.addEventListener("click", this.click_image_clear, false);
          }
          if (input.parentElement.getAttribute("field") == "text") {
            validator.validate_text_question(input, this.comp.containers, false);
          }
        }
      }
    }
    click_start_button(event) {
      this.show_view("identifier");
    }
    set_loading() {
      this.hide_all();
      this.comp.navbars.main.classList.remove("hidden");
      document.querySelector(".load.content-container").classList.remove("hidden");
    }
    identify() {
      let identifier_data = {};
      for (let input of this.comp.input_map.identifier) {
        let field = input.getAttribute("name");
        if (field == "rut") {
          identifier_data.rut = input.value;
        } else if (field == "email") {
          identifier_data.email = input.value;
        }
      }
      if (this.closed_sk) {
        identifier_data.sk = this.closed_sk;
      }
      fetch(this.auth_url, {
        method: "POST",
        body: JSON.stringify(identifier_data),
        headers: {
          "Content-Type": "application/json",
          "X-CSRFToken": this.csrf_token
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.status == 200) {
          this.show_view("detail");
        } else {
          response.json().then(data => {
            let errors = this.comp.containers.identifier.querySelector(".errors");
            if (data.email) {
              errors.textContent = data.email;
            }
            if (data.rut) {
              errors.textContent = data.rut;
            }
            this.show_view("identifier");
          });
        }
      });
    }
    click_next_button(event) {
      let total_questions = this.comp.containers.question_list.length;
      let valid = event.currentTarget.getAttribute("disabled") != "true";
      if (valid) {
        if (this.focus != total_questions - 1) {
          event.preventDefault();
        } else {
          for (let input of this.comp.input_map.identifier) {
            if (this.closed_email && input.getAttribute("name") == "email") {
              input.removeAttribute("disabled");
            }
          }
          this.set_loading();
        }
        if (this.focus == "identifier") {
          this.set_loading();
          this.identify();
        } else if (this.focus == "detail") {
          this.show_view(0);
        } else if (Number.isInteger(this.focus)) {
          if (this.focus < total_questions - 1) {
            this.show_view(this.focus + 1);
          }
        }
      }
    }
    change_identifier_input(event) {
      let input = event.currentTarget;
      this.comp.buttons.submit;
      let errors = input.parentElement.parentElement.querySelector(".errors");
      let valid = true;
      for (let input of this.comp.input_map.identifier) {
        if (input.getAttribute("name") == "rut") {
          validator.validate_rut(input);
        }
        valid &&= input.validity.valid;
      }
      if (valid) {
        errors.textContent = "";
      } else {
        errors.textContent = "*Error de autenticación";
      }
      this.set_next_button_status("identifier", true);
    }
    change_question_input(event) {
      let input = event.currentTarget;
      this.validate_input(input, true);
      this.set_next_button_status(input.question_index, true);
    }
    validate_input(input, report) {
      if (input.type == "file") {
        validator.validate_image_question(input, report);
      }
      if (input.type == "checkbox") {
        validator.validate_options_question(input, this.comp.containers, report);
      }
      if (input.classList.contains("vSerializedField")) {
        validator.validate_point_question(input, this.comp.containers, report);
      }
      if (input.parentElement.getAttribute("field") == "text") {
        validator.validate_text_question(input, this.comp.containers, report);
      }
    }
    click_image_clear(event) {
      let input_container = event.currentTarget.parentElement;
      let input = input_container.querySelector("input");
      input.value = "";
      validator.validate_image_question(input, true);
      this.set_next_button_status(input.question_index, true);
    }
    hide_all() {
      this.comp.navbars.main.classList.add(this.hidden_class_name);
      this.comp.navbars.brand.classList.add(this.hidden_class_name);
      this.comp.containers.entry.classList.add(this.hidden_class_name);
      this.comp.containers.identifier.classList.add(this.hidden_class_name);
      this.comp.containers.detail.classList.add(this.hidden_class_name);
      for (let question of this.comp.containers.question_list) {
        question.classList.add(this.hidden_class_name);
      }
      this.comp.buttons.submit.classList.add(this.hidden_class_name);
      this.comp.buttons.back.classList.add(this.hidden_class_name);
      document.querySelector(".load.content-container").classList.add(this.hidden_class_name);
    }
    show_view(focus) {
      this.hide_all();
      this.focus = focus;
      if (focus != "entry") {
        this.comp.buttons.back.classList.remove(this.hidden_class_name);
        this.comp.buttons.submit.classList.remove(this.hidden_class_name);
        this.comp.navbars.main.classList.remove(this.hidden_class_name);
      } else {
        this.comp.navbars.brand.classList.remove(this.hidden_class_name);
      }
      if (Number.isInteger(focus)) {
        for (let input of this.comp.input_map.question_list[focus]) {
          this.validate_input(input, false);
        }
        this.set_next_button_status(focus);
        this.comp.containers.question_list[focus].classList.remove(this.hidden_class_name);
      } else {
        this.comp.containers[focus].classList.remove(this.hidden_class_name);
        this.comp.buttons.submit.removeAttribute("disabled");
      }
      if (focus == "identifier") {
        this.set_next_button_status(focus);
      }
    }
    show_back_form() {
      if (this.focus == "identifier") {
        this.show_view("entry");
      } else if (this.focus == "detail") {
        this.show_view("identifier");
      } else if (!isNaN(this.focus)) {
        if (this.focus == 0) {
          this.show_view("detail");
        } else {
          this.show_view(this.focus - 1);
        }
      }
    }
    set_next_button_status(focus, report) {
      let next_button = this.comp.buttons.submit;
      let valid = true;
      let input_list = !isNaN(this.focus) ? this.comp.input_map.question_list[focus] : this.comp.input_map.identifier;
      for (let input of input_list) {
        valid &&= input.validity.valid;
      }
      if (valid) {
        next_button.removeAttribute("disabled");
      } else {
        next_button.setAttribute("disabled", true);
      }
    }
  }

  class QueryListManager {
    constructor({
      manager = null
    }) {
      this.manager = manager;
      this.data = [];
      this._click_query_detail = this._click_query_detail.bind(this);
    }
    show_view(on_history) {
      fetch(this.manager.url_base, {
        method: "GET",
        headers: {
          "Content-Type": "application/json"
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            this.data = data.list;
            this._set_in_view();
            if (on_history) {
              this.manager.engine._set_url_params("query-list", null);
            }
          });
        } else {
          console.log(response);
        }
      });
    }
    _set_in_view() {
      let template = document.querySelector("#query-item-template").cloneNode(true);
      template.classList.remove("hidden");
      let query_list = this.manager.engine.views.query_list.querySelector(".query-item-list");
      query_list.innerHTML = "";
      for (let item of this.data) {
        let query_item = template.cloneNode(true);
        let returned_query_item = this.manager._create_query_item(item, query_item);
        let detail_link = returned_query_item.querySelector(".action-button.item-detail-link");
        detail_link.query_uuid = item.uuid;
        detail_link.addEventListener("click", this._click_query_detail, false);
        if (this.manager.engine.user.is_superuser && item.created_by_email) {
          let email = document.createElement("div");
          email.classList.add("query-item-created-by");
          email.textContent = item.created_by_email;
          returned_query_item.appendChild(email);
        }
        query_list.appendChild(returned_query_item);
      }
      this.manager._build_sidebar();
      this.manager.engine._hide_all_views();
      this.manager.engine.views.query_list.classList.remove("hidden");
    }
    _click_query_detail(event) {
      this.manager.engine.cursor.key = event.currentTarget.query_uuid;
      this.manager.engine.show_view("query-detail", true);
    }
  }

  class QueryDetailManager {
    constructor({
      manager = null
    }) {
      this.manager = manager;
      this.data = {};
      this.charts = {
        summary: null
      };
      this._click_query_edit = this._click_query_edit.bind(this);
    }
    show_view(on_history) {
      fetch(`${this.manager.url_base}${this.manager.engine.cursor.key}`, {
        method: "GET",
        headers: {
          "Content-Type": "application/json"
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            this.data = data;
            this._set_in_view();
            if (on_history) {
              this.manager.engine._set_url_params("query-detail", data.query.url_code);
            }
          });
        } else {
          console.log(response);
          this.manager.engine.show_view("query-list", false);
        }
      });
    }
    _set_in_view() {
      let query_item = document.querySelector("#query-detail-item");
      this.manager._create_query_item(this.data.query, query_item);
      if (this.data.query.is_active) {
        document.querySelector("#detail-action-submit").setAttribute("href", this.data.links.submit);
        document.querySelector("#detail-action-submit").classList.remove("hidden");
      } else {
        document.querySelector("#detail-action-submit").classList.add("hidden");
      }
      this._set_query_preview();
      this.manager._build_sidebar();
      this.manager.engine._hide_all_views();
      this.manager.engine.views.query_detail.classList.remove("hidden");
    }
    _click_query_edit(event) {
      this.manager.engine.show_view("query-update", true);
    }
    _set_query_preview() {
      document.querySelector("#query-detail .query-preview-description").textContent = this.data.query.description;
      let questions = document.querySelector("#query-detail .query-preview-questions");
      questions.innerHTML = "";
      let index = 0;
      for (let answer_result of this.data.answer_results) {
        let question = answer_result.question;
        let question_container = document.createElement("div");
        question_container.classList.add("question-container");
        question_container.innerHTML = `
        <div class="subtitle">Pregunta ${index + 1}</div>
        <div class="question-item-kind">${this.manager.get_kind_label(question)}</div>
        <div class="question-name">${question.name}</div>
        <div class="question-description">${question.description ? question.description : ""}</div>
      `;
        if (question.kind == "POINT") {
          question_container.innerHTML += "<div class='question-map map-bg'></div>";
        } else if (question.kind == "SELECT") {
          question_container.innerHTML += `<div class="question-options"></div>`;
          let options_container = question_container.querySelector(".question-options");
          let option_index = 0;
          for (let option of question.options) {
            options_container.innerHTML += `
            <div class="option">
              <span class="option-label">${this.manager.letters[option_index]}.</span>
              <span class="option-value">${option.name}</span>
            </div>
          `;
            option_index += 1;
          }
        }
        questions.appendChild(question_container);
        index += 1;
      }
    }
  }

  class QueryEditBase {
    constructor({
      manager = null
    }) {
      this.manager = manager;
      this.required_fields = ["name"];
      this.data = this._get_default_data();
      this.inputs = {};
      this.errors = {};
      this.buttons = {};
      this.can_edit_questions = true;
      this._click_publish = this._click_publish.bind(this);
      this._dropdown_create_question = this._dropdown_create_question.bind(this);
      this._click_create_question = this._click_create_question.bind(this);
      this._move_question_ondragstart = this._move_question_ondragstart.bind(this);
      this._move_question_ondragend = this._move_question_ondragend.bind(this);
      this._move_question_ondrop = this._move_question_ondrop.bind(this);
      this._click_remove_question = this._click_remove_question.bind(this);
      this._click_question_add_option = this._click_question_add_option.bind(this);
      this._click_question_max_answers_menu = this._click_question_max_answers_menu.bind(this);
      this._click_question_max_answers_set = this._click_question_max_answers_set.bind(this);
      this._click_question_remove_option = this._click_question_remove_option.bind(this);
      this._set_initial();
      this._set_publish_button();
      this._set_create_question_button();
      this._set_query_inputs();
    }
    _get_default_data() {
      return {
        name: null,
        description: null,
        start_at: null,
        end_at: null,
        active: true,
        questions: [],
        auth_rut: "OPTIONAL",
        auth_email: "OPTIONAL"
      };
    }
    _set_initial() {}
    _set_publish_button() {
      let publish = document.querySelector(`#${this.view_type}-query-button`);
      publish.disabled = true;
      publish.classList.add("disabled");
      publish.addEventListener("click", this._click_publish, false);
      this.buttons.publish = publish;
    }
    _click_publish(event) {
      let publish = document.querySelector(`#${this.view_type}-query-button`);
      if (publish.disabled == false) {
        this.manager.engine._set_loading();
        this.execute_service();
      }
    }
    execute_service() {}
    _clean_data() {
      this.data = this._get_default_data();
      this._build_question_from_data();
      for (let field in this.inputs) {
        let input = this.inputs[field];
        if (["start_at", "end_at"].includes(field) && this.data[field]) {
          input.value = new Date(this.data[field]).toISOString().split('T')[0];
        } else {
          input.value = this.data[field];
        }
      }
      this.validate_inputs();
    }
    _set_query_inputs() {
      let name = document.querySelector(`#query-${this.view_type}-name`);
      let description = document.querySelector(`#query-${this.view_type}-description`);
      let start_at = document.querySelector(`#query-${this.view_type}-start_at`);
      let end_at = document.querySelector(`#query-${this.view_type}-end_at`);
      let active = document.querySelector(`#query-${this.view_type}-active`);
      let auth_email = document.querySelector(`#query-${this.view_type}-auth-email`);
      let auth_rut = document.querySelector(`#query-${this.view_type}-auth-rut`);
      this._change_input = this._change_input.bind(this);
      for (let input of [name, description, start_at, end_at, active, auth_email, auth_rut]) {
        input.field = input.getAttribute("field");
        input.addEventListener("input", this._change_input, false);
        this.inputs[input.field] = input;
      }
      this.error_containers = {};
      for (let field in this.data) {
        if (field != "questions") {
          let container = document.querySelector(`#query-${this.view_type}-${field}-error`);
          if (container) {
            this.error_containers[field] = container;
          }
        }
      }
      this.error_containers["times"] = document.querySelector(`#query-${this.view_type}-times-error`);
    }
    _set_errors_message() {
      for (let field in this.error_containers) {
        if (field != "questions") {
          this.error_containers[field].innerText = "";
        } else {
          for (let index in this.error_containers[field]) {
            for (let question_field in this.error_containers[field][index]) {
              this.error_containers[field][index][question_field].innerText = "";
            }
          }
        }
      }
      for (let field in this.errors) {
        if (!["questions", "start_at", "end_at"].includes(field)) {
          this.error_containers[field].innerText = this.errors[field];
        } else if (["start_at", "end_at"].includes(field)) {
          this.error_containers.times.innerText = this.errors[field];
        } else if (typeof this.errors[field] == "object") {
          for (let index in this.errors[field]) {
            for (let question_field in this.errors[field][index]) {
              this.error_containers[field][parseInt(index)][question_field].innerText = this.errors[field][index][question_field];
            }
          }
        }
      }
    }
    _change_input(event) {
      let field = event.target.field;
      let value = event.target.value != "" ? event.target.value : null;
      if (event.target.question) {
        if (field == "required") {
          value = event.target.checked ? true : false;
        }
        if (field == "question-option") {
          this.data.questions[event.target.index].options[event.target.option_index].name = value;
        } else {
          this.data.questions[event.target.index][field] = value;
        }
      } else {
        this.data[field] = value;
      }
      this.validate_inputs();
      this._set_errors_message();
    }
    validate_inputs() {
      this.errors = {};
      let no_question_message = "Debe crear al menos una pregunta";
      if (this.data.questions.length == 0) {
        this.errors.questions = no_question_message;
      } else {
        delete this.errors.questions;
      }
      for (let field in this.data) {
        if (field == "questions") {
          for (let question of this.data.questions) {
            for (let field in question) {
              let value = question[field];
              this._val_field_value_is_required(field, value, question.order);
            }
            if (question.kind == "SELECT") {
              this._val_question_options(question);
            }
          }
        } else {
          let value = this.data[field];
          this._val_field_value_is_required(field, value);
          if (value && ["start_at", "end_at"].includes(field)) {
            this._val_date_field_value(field, value);
          }
        }
      }
      if (this.errors.questions && this.errors.questions.length == 0) {
        delete this.errors.questions;
      }
      if (this.errors.questions && this.errors.questions != no_question_message) {
        this.buttons.new_question.disabled = true;
        this.buttons.new_question.classList.add("disabled");
      } else {
        this.buttons.new_question.disabled = false;
        this.buttons.new_question.classList.remove("disabled");
      }
      if (!this.can_edit_questions) {
        this.buttons.new_question.disabled = true;
        this.buttons.new_question.classList.add("disabled");
      }
      if (Object.keys(this.errors).length === 0 && this.errors.constructor === Object) {
        this.buttons.publish.classList.remove("disabled");
        this.buttons.publish.disabled = false;
      } else {
        this.buttons.publish.classList.add("disabled");
        this.buttons.publish.disabled = true;
      }
    }
    _val_date_field_value(field, value) {
      let start_at = this.data["start_at"] ? new Date(this.data["start_at"]) : null;
      let end_at = this.data["end_at"] ? new Date(this.data["end_at"]) : null;
      if (start_at && end_at && start_at >= end_at) {
        let message = "La fecha de inicio debe ser menor que la de término";
        this._set_field_error(field, message);
      } else {
        this._clean_field_error("start_at");
      }
    }
    _val_field_value_is_required(field, value, question_index) {
      if (this.required_fields.includes(field) && (!value || value.trim() == "")) {
        let message = "Este campo es requerido";
        this._set_field_error(field, message, question_index);
      } else {
        this._clean_field_error(field, question_index);
      }
    }
    _val_question_options(question) {
      let message = "Debe agregar al menos dos opciones y no pueden estar vacías";
      if (question.options.length < 2) {
        this._set_field_error("options", message, question.order);
      }
      let option_values = [];
      for (let option of question.options) {
        if (!option.name || option.name.trim() == "") {
          this._set_field_error("options", message, question.order);
          break;
        }
        if (option_values.includes(option.name)) {
          message = "Las opciones no pueden ser iguales";
          this._set_field_error("options", message, question.order);
          break;
        }
        option_values.push(option.name);
      }
    }
    _set_field_error(field, message, question_index) {
      if (!isNaN(question_index)) {
        if (!this.errors.questions) {
          this.errors.questions = {};
        }
        if (!this.errors.questions[question_index]) {
          this.errors.questions[question_index] = {};
        }
        this.errors.questions[question_index][field] = message;
      } else {
        this.errors[field] = message;
      }
    }
    _clean_field_error(field, question_index) {
      if (!isNaN(question_index) && this.errors.questions && this.errors.questions[question_index]) {
        delete this.errors.questions[question_index][field];
      }
      if (isNaN(question_index)) {
        delete this.errors[field];
      }
    }
    _set_create_question_button() {
      let button = document.querySelector(`#query-${this.view_type}-create-question-button`);
      button.addEventListener("click", this._dropdown_create_question, false);
      button.disabled = false;
      this.buttons.new_question = button;
      let kinds = Array.from(document.querySelectorAll(`#query-${this.view_type}-create-question-kinds .dropdown-item`));
      for (let kind of kinds) {
        kind.kind = kind.getAttribute("kind");
        kind.type = kind.getAttribute("type");
        kind.addEventListener("click", this._click_create_question, false);
      }
    }
    _dropdown_create_question(event) {
      let button = document.querySelector(`#query-${this.view_type}-create-question-button`);
      if (this.can_edit_questions) {
        let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`);
        if (!button.disabled) {
          if (dropdown.classList.contains("hidden")) {
            dropdown.classList.remove("hidden");
          } else {
            dropdown.classList.add("hidden");
          }
        }
      }
    }
    _click_create_question(event) {
      let question = {
        kind: event.target.kind,
        name: null,
        description: null,
        required: false,
        order: this.data.questions.length
      };
      if (event.target.kind === "TEXT") {
        if (event.target.type == "large") {
          question.text_max_length = 400;
        } else {
          question.text_max_length = 150;
        }
      } else if (event.target.kind == "SELECT") {
        question.options = [];
      }
      this.data.questions.push(question);
      this._build_question_from_data();
      let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`);
      dropdown.classList.add("hidden");
      document.querySelector(`#query-${this.view_type}-questions-tab .question-item:last-child`).scrollIntoView();
    }
    _build_question_from_data() {
      let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`);
      questions_container.innerHTML = "";
      let index = 0;
      for (let question_data of this.data.questions) {
        let question = this._create_question_element(question_data, index);
        questions_container.appendChild(question);
        let delete_button = question.querySelector(".action-delete");
        this._prepare_question_inputs(question, question_data, ["name", "description", "required"]);
        if (this.can_edit_questions) {
          let click_delete = this._get_question_delete_callback();
          delete_button.addEventListener("click", click_delete, false);
          this._set_question_draggable(question);
          this._set_question_error_containers(question);
        } else {
          delete_button.remove();
          this._set_disable_edit_questions(question);
        }
        index += 1;
      }
      this.validate_inputs();
    }
    _get_question_delete_callback() {
      return this._click_remove_question;
    }
    _get_question_id(index) {
      return `query-${this.view_type}-question-item-${index}`;
    }
    _create_question_element(question_data, index) {
      let question_id = this._get_question_id(index);
      var question = document.createElement("div");
      question.classList.add("question-item");
      question.index = index;
      question.setAttribute("id", question_id);
      question.kind = question_data.kind;
      let kind_label = this.manager.get_kind_label(question_data);
      question.innerHTML = `
      <div class="question-move-previous"></div>
      <div class="question-container">
        <div class="question-item-move">
          <i class="icon move"></i>
        </div>
        <div class="question-item-content">
          <div class="question-item-kind">${kind_label}</div>
          <input class="question-item-name"
                 id="query-${this.view_type}-${question_id}-name-input"
                 type="text"
                 field="name"
                 placeholder="Escribe tu pregunta aquí">
          </input>
          <div class="error-label" id="query-${this.view_type}-question-${index}-name-error"></div>
          <input class="question-item-description"
                 id="query-${this.view_type}-${question_id}-description-input"
                 type="text"
                 field="description"
                 placeholder="Agrega una descripción para esta pregunta (opcional)">
          </input>
          <div class="error-label" id="query-${this.view_type}-question-${index}-description-error"></div>
        </div>
        <div class="question-item-actions">
          <div class="actions-top">
            <div class="action-delete"><i class="icon close-dark"></i></div>
          </div>
          <div class="actions-bottom">
            <div class="action-required">
              <label class="action-checkbox">
                <div class="action-label">Obligatorio</div>
                <input type="checkbox"
                       id="query-${this.view_type}-${question_id}-required-input"
                       field="required"
                       class="action-checkbox-input">
                </input>
                <span class="action-checkbox-checkmarker"></span>
              </label>
            </div>
          </div>
        </div>
      </div>
      <div class="question-move-next"></div>
    `;
      let question_content = question.querySelector(".question-item-content");
      if (question_data.kind === "TEXT") {
        let type = question_data.text_max_length > 150 ? "largo" : "corto";
        question_content.innerHTML += `<div class="kind-text">Respuesta de texto ${type} (${question_data.text_max_length} caracteres)</div>`;
      } else if (question_data.kind === "IMAGE") {
        question_content.innerHTML += `<div class="kind-image">Respuesta de imagen o foto</div>`;
      } else if (question_data.kind === "POINT") {
        question_content.innerHTML += `<div class="kind-point"></div>`;
      } else if (question_data.kind === "SELECT") {
        this._set_question_options(question, question_data);
        this._set_question_max_answers(question, question_data);
      }
      return question;
    }
    _prepare_question_inputs(question, question_data, fields) {
      let question_id = this._get_question_id(question.index);
      for (let field of fields) {
        let element = question.querySelector(`#query-${this.view_type}-${question_id}-${field}-input`);
        element.field = field;
        element.index = question.index;
        element.question = true;
        if (field === "required") {
          element.checked = question_data[field];
        } else {
          element.value = question_data[field];
        }
        if (this.can_edit_questions) {
          element.addEventListener("input", this._change_input, false);
        } else {
          element.setAttribute("disabled", true);
        }
      }
    }
    _set_question_error_containers(question) {
      if (!this.error_containers.questions) {
        this.error_containers.questions = {};
      }
      if (!this.error_containers.questions[question.index]) {
        this.error_containers.questions[question.index] = {};
      }
      let fields = ["name", "description"];
      if (question.kind == "SELECT") {
        fields.push("options");
      }
      for (let field of fields) {
        this.error_containers.questions[question.index][field] = question.querySelector(`#query-${this.view_type}-question-${question.index}-${field}-error`);
      }
    }
    _set_disable_edit_questions(question) {
      for (let input of question.querySelectorAll("input")) {
        input.setAttribute("disabled", true);
      }
    }
    _click_remove_question(event) {
      let question = event.target.closest(".question-item");
      this.data.questions.splice(question.index, 1);
      this._build_question_from_data();
    }
    _set_question_options(question, question_data) {
      let question_content = question.querySelector(".question-item-content");
      let options_container = document.createElement("div");
      options_container.classList.add(".question-options-container");
      options_container.innerHTML = `
      <div class="question-option-list"></div>
      <div class="error-label" id="query-${this.view_type}-question-${question.index}-options-error"></div>
      <div class="question-option-add">+ Agregar opción</div>
    `;
      let question_add_button = options_container.querySelector(".question-option-add");
      question_add_button.index = question.index;
      question_add_button.addEventListener("click", this._click_question_add_option, false);
      question_content.appendChild(options_container);
      let option_list = options_container.querySelector(`.question-option-list`);
      let option_index = 0;
      for (let option_data of this.data.questions[question.index].options) {
        let option = document.createElement("div");
        option.classList.add("question-option");
        let option_id = `query-${this.view_type}-question-option-${question.index}-${option_index}`;
        option.innerHTML = `
        <div class="question-option-label">${this.manager.letters[option_index]}.</div>
        <input id="${option_id}" type="text" class="question-option-input" placeholder="Opción ${option_index + 1}">
        <div class="question-option-delete">X</div>
      `;
        let input = option.querySelector(".question-option-input");
        input.field = "question-option";
        input.index = question.index;
        input.question = true;
        input.option_index = option_index;
        input.value = option_data.name;
        input.addEventListener("input", this._change_input, false);
        let delete_button = option.querySelector(".question-option-delete");
        if (this.can_edit_questions) {
          delete_button.option_index = option_index;
          delete_button.addEventListener("click", this._click_question_remove_option, false);
        } else {
          delete_button.remove();
        }
        option_index += 1;
        option_list.appendChild(option);
      }
    }
    _click_question_remove_option(event) {
      let question = event.target.closest(".question-item");
      this.data.questions[question.index].options.splice(event.target.option_index, 1);
      this._build_question_from_data();
      this.validate_inputs();
      this._set_errors_message();
    }
    _set_question_max_answers(question, question_data) {
      let actions = question.querySelector(".question-item-actions .actions-bottom");
      actions.innerHTML = `
      <div class="action-max-answers">
        <div class="action-max-answers-button">
          <span class="action-label">Cantidad de respuestas</span> <i class="icon bottom"></i>
        </div>
        <div class="action-max-answers-dropdown hidden"></div>
      </div>
    ` + actions.innerHTML;
      let button = actions.querySelector(".action-max-answers-button");
      button.addEventListener("click", this._click_question_max_answers_menu, false);
      let dropdown = actions.querySelector(".action-max-answers-dropdown");
      for (let i = 0; i < 5; i++) {
        let option = document.createElement("div");
        option.classList.add("action-max-answers-option");
        option.value = i + 1;
        let message = `${i + 1} respuesta`;
        if (option.value == this.data.questions[question.index].max_answers) {
          actions.querySelector(".action-label").innerText = message;
        }
        if (i > 0) {
          message += "s";
        }
        option.innerText = message;
        option.addEventListener("click", this._click_question_max_answers_set, false);
        dropdown.appendChild(option);
      }
    }
    _click_question_add_option(event) {
      let question = event.target.closest(".question-item");
      let order = this.data.questions[question.index].options.length;
      let empty_option = {
        name: null,
        order: order
      };
      this.data.questions[question.index].options.push(empty_option);
      this._build_question_from_data();
      this.validate_inputs();
      this._set_errors_message();
    }
    _click_question_max_answers_menu(event) {
      let question = event.target.closest(".question-item");
      let dropdown = question.querySelector(".action-max-answers-dropdown");
      if (this.can_edit_questions) {
        if (dropdown.classList.contains("hidden")) {
          dropdown.classList.remove("hidden");
        } else {
          dropdown.classList.add("hidden");
        }
      }
    }
    _click_question_max_answers_set(event) {
      let question = event.target.closest(".question-item");
      let button_label = question.querySelector(".action-max-answers .action-label");
      let dropdown = question.querySelector(".action-max-answers-dropdown");
      this.data.questions[question.index].max_answers = event.target.value;
      button_label.innerText = event.target.innerText;
      dropdown.classList.add("hidden");
    }
    _set_question_draggable(question) {
      let container = question.querySelector(".question-container");
      container.draggable = true;
      container.ondragstart = this._move_question_ondragstart;
      container.ondragend = this._move_question_ondragend;
      let move_previous = question.querySelector(".question-move-previous");
      let move_next = question.querySelector(".question-move-next");
      move_previous.ondragenter = () => move_previous.classList.add("active");
      move_previous.ondragleave = () => move_previous.classList.remove("active");
      move_next.ondragenter = () => move_next.classList.add("active");
      move_next.ondragleave = () => move_next.classList.remove("active");
      move_previous.ondragover = event => event.preventDefault();
      move_previous.ondrop = this._move_question_ondrop;
      move_previous.kind = "previous";
      move_next.ondragover = event => event.preventDefault();
      move_next.kind = "next";
      move_next.ondrop = this._move_question_ondrop;
    }
    _move_question_ondragstart(event) {
      let question = event.target.closest(".question-item");
      let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`);
      this.current_pos = question.index;
      setTimeout(() => {
        question.style.display = "none";
      }, 0);
      questions_container.style.heigth = questions_container.clientHeigth - question.clientHeigth + "px";
    }
    _move_question_ondragend(event) {
      let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`);
      for (let question of questions_container.children) {
        question.style.display = "flex";
        question.querySelector(".question-move-previous").classList.remove("active");
        question.querySelector(".question-move-next").classList.remove("active");
      }
    }
    _move_question_ondrop(event) {
      event.preventDefault();
      let question = event.target.closest(".question-item");
      let kind = event.target.kind;
      this.data.questions.length;
      let to_index = null;
      if (kind == "previous") {
        to_index = question.index - 1 < 0 ? 0 : question.index;
      } else if (kind == "next") {
        to_index = question.index;
      }
      if (this.current_pos === to_index) {
        return;
      }
      let questions = [...this.data.questions];
      let moved_question = {
        ...questions[this.current_pos]
      };
      questions = questions.filter(q => q.order != moved_question.order);
      questions.splice(to_index, 0, moved_question);
      this.data.questions = questions;
      this._set_question_data_order();
      this._build_question_from_data();
    }
    _set_question_data_order() {
      let index = 0;
      for (let question of this.data.questions) {
        question.order = index;
        index += 1;
      }
    }
  }
  class QueryCreateManager extends QueryEditBase {
    _set_initial() {
      this.view_type = "create";
    }
    show_view(on_history) {
      this.manager.engine._hide_all_views();
      this.manager._build_sidebar();
      this._clean_data();
      this.manager.engine.views.query_create.classList.remove("hidden");
      if (on_history) {
        this.manager.engine._set_url_params("query-create", null);
      }
    }
    execute_service() {
      fetch(this.manager.url_base, {
        method: "POST",
        body: JSON.stringify(this.data),
        headers: {
          "Content-Type": "application/json",
          "X-CSRFToken": this.manager.engine.csrf_token
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            if (data.uuid) {
              this.manager.engine.cursor.key = data.uuid;
              this.manager.engine.show_view("query-detail", true);
              this._clean_data();
            } else {
              console.log(data);
            }
          });
        } else {
          response.json().then(data => {
            this.errors = {
              ...this.errors,
              ...data
            };
            this._set_errors_message();
            this.manager.engine._hide_all_views();
            this.manager.engine.views.query_create.classList.remove("hidden");
          });
        }
      });
    }
  }
  class QueryUpdateManager extends QueryEditBase {
    _set_initial() {
      this.view_type = "update";
      this._click_query_delete_modal = this._click_query_delete_modal.bind(this);
      this._click_query_delete = this._click_query_delete.bind(this);
      this._click_remove_question_modal = this._click_remove_question_modal.bind(this);
      let query_delete_button = document.querySelector("#update-query-delete-button");
      query_delete_button.addEventListener("click", this._click_query_delete_modal, false);
    }
    _click_query_delete_modal(event) {
      let config = {
        class: "query-delete-confirmation",
        icon: "alert",
        title: "¿Estás seguro de que quieres eliminar esta consulta?",
        content: `Se perderán todas las respuestas (${this.total_responses}) y datos asociados a esta consulta de manera permanente`,
        actions: [{
          name: "Sí",
          click: this._click_query_delete
        }, {
          name: "No",
          click: this.manager.engine.hide_modal
        }]
      };
      this.manager.engine.show_modal(config);
    }
    _click_query_delete(event) {
      this.manager.engine._set_loading();
      this.manager.engine.hide_modal();
      fetch(`${this.manager.url_base}${this.manager.engine.cursor.key}`, {
        method: "DELETE",
        body: JSON.stringify({
          "confirmation": "TRUE"
        }),
        headers: {
          "Content-Type": "application/json",
          "X-CSRFToken": this.manager.engine.csrf_token
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            this.manager.engine.show_view("query-list", true);
          });
        } else {
          console.log(response);
          this.manager.engine.show_view("query-update", true);
        }
      });
    }
    _get_question_delete_callback() {
      return this._click_remove_question_modal;
    }
    _click_remove_question_modal(event) {
      let question = event.target.closest(".question-item");
      let config = {
        class: "query-delete-confirmation",
        icon: "alert",
        title: "¿Estás seguro de que quieres eliminar esta pregunta?",
        content: `Se perderán todas las respuestas y datos asociados a esta pregunta de manera permanente`,
        actions: [{
          name: "Sí",
          click: this._click_remove_question
        }, {
          name: "No",
          click: this.manager.engine.hide_modal
        }],
        data: {
          question_index: question.index
        }
      };
      this.manager.engine.show_modal(config);
    }
    _click_remove_question(event) {
      let modal_data = event.target.closest("#admin-modal").data;
      let question_index = modal_data.question_index;
      this.data.questions.splice(question_index, 1);
      this._build_question_from_data();
      this.manager.engine.hide_modal();
    }
    show_view(on_history) {
      fetch(`${this.manager.url_base}${this.manager.engine.cursor.key}`, {
        method: "GET",
        headers: {
          "Content-Type": "application/json"
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            this._set_in_view(data);
            if (on_history) {
              this.manager.engine._set_url_params("query-update", data.query.url_code);
            }
          });
        } else {
          console.log(response);
          this.manager.engine._set_url_params("query-list");
          this.manager.engine.show_view("query-list", false);
        }
      });
    }
    execute_service() {
      fetch(`${this.manager.url_base}${this.manager.engine.cursor.key}/`, {
        method: "PUT",
        body: JSON.stringify(this.data),
        headers: {
          "Content-Type": "application/json",
          "X-CSRFToken": this.manager.engine.csrf_token
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            if (data.uuid) {
              this.manager.engine.cursor.key = data.uuid;
              this.manager.engine.show_view("query-detail", true);
              this._clean_data();
            } else {
              console.log(data);
            }
          });
        } else {
          response.json().then(data => {
            this.errors = {
              ...this.errors,
              ...data
            };
            this._set_errors_message();
            this.manager.engine._hide_all_views();
            this.manager.engine.views.query_update.classList.remove("hidden");
          });
        }
      });
    }
    _set_in_view(data) {
      this.data = {
        uuid: data.query.uuid,
        name: data.query.name,
        description: data.query.description,
        start_at: data.query.start_at,
        end_at: data.query.end_at,
        active: data.query.active,
        auth_email: data.query.auth_email,
        auth_rut: data.query.auth_rut,
        questions: []
      };
      this.total_responses = data.query.total_responses;
      let questions = Array.isArray(data.query.questions) ? data.query.questions : [];
      for (let question of questions) {
        let cleaned_question = this._get_cleaned_question(question);
        this.data.questions.push(cleaned_question);
      }
      for (let field in this.inputs) {
        let input = this.inputs[field];
        if (["start_at", "end_at"].includes(field) && this.data[field]) {
          input.value = new Date(this.data[field]).toISOString().split('T')[0];
        } else {
          input.value = this.data[field];
        }
      }
      this.can_edit_questions = data.query.can_edit_questions;
      if (!this.can_edit_questions) {
        this.buttons.new_question.disabled = true;
        this.buttons.new_question.classList.add("disabled");
      }
      this._build_question_from_data();
      this.manager._build_sidebar();
      this.manager.engine._hide_all_views();
      this.manager.engine.views.query_update.classList.remove("hidden");
    }
    _get_cleaned_question(question) {
      let cleaned_question = {
        uuid: question.uuid,
        kind: question.kind,
        name: question.name,
        description: question.description,
        required: question.required,
        order: question.order
      };
      if (question.kind == "TEXT") {
        cleaned_question.text_max_length = question.text_max_length;
      }
      if (question.kind == "SELECT") {
        cleaned_question.max_answers = question.max_answers;
        cleaned_question.options = question.options;
      }
      return cleaned_question;
    }
  }

  function get_chart(config) {
    let id = config.id;
    let type = config.type;
    let values = config.values;
    let labels = config.labels;
    let options = config.options ? config.options : {};
    let barColors = ["#c1368c", "#a34895", "#143358", "#495599", "#54baae"];
    let data = {
      labels: labels,
      datasets: [{
        backgroundColor: barColors,
        data: values,
        label: config.label
      }]
    };
    options.scales = {
      x: {
        ticks: {
          display: false
        },
        grid: {
          display: false
        }
      },
      y: {
        ticks: {
          display: false
        }
      }
    };
    options.plugins = {
      datalabels: {
        color: "#fff"
      },
      legend: {
        display: false
      },
      tooltip: {
        enabled: false
      }
    };
    options.animation = {
      duration: 0
    };
    Chart.register(ChartDataLabels);
    let chart = new Chart(id, {
      type: type,
      data: data,
      options: options
    });
    let labels_container = document.querySelector(`#${id}-labels`);
    let color_index = 0;
    let value_index = 0;
    for (let label of labels) {
      let element = document.createElement("div");
      element.classList.add("chart-label-container");
      let color_element = document.createElement("div");
      color_element.classList.add("chart-label-color");
      if (color_index >= barColors.length) {
        color_index = 0;
      }
      color_element.style.backgroundColor = barColors[color_index];
      element.appendChild(color_element);
      let label_value = document.createElement("div");
      label_value.classList.add("chart-label-value");
      label_value.textContent = `${values[value_index]} - ${label}`;
      element.appendChild(label_value);
      labels_container.append(element);
      color_index += 1;
      value_index += 1;
    }
    labels_container.classList.remove("hidden");
    return chart;
  }

  class QueryResultManager {
    constructor({
      manager = null,
      kind = null
    }) {
      this.manager = manager;
      this.data = {};
      this.kind = kind;
      this.charts = {
        summary: null,
        questions: []
      };
      this._set_pre_in_view();
      this.map = null;
      this.data_table = null;
    }
    _set_pre_in_view() {
      let tab_links = document.querySelector(`.view.query-${this.kind} .result.tab-links`);
      let click_got_to = this.manager._click_go_to_view.bind(this.manager);
      for (let tab_link of tab_links.children) {
        tab_link.addEventListener("click", click_got_to, false);
      }
      this._set_download_links();
    }
    _set_download_links() {
      this._click_excel_link = this._click_excel_link.bind(this);
      this._click_download_dropdown = this._click_download_dropdown.bind(this);
      let dropdown_button = document.querySelector(`#query-${this.kind}-download-button`);
      dropdown_button.addEventListener("click", this._click_download_dropdown, false);
      let excel_link = document.querySelector(`#query-${this.kind}-download-excel`);
      excel_link.addEventListener("click", this._click_excel_link, false);
    }
    _click_download_dropdown(event) {
      let dropdown_content = document.querySelector(`#query-${this.kind}-dropdown`);
      if (dropdown_content.classList.contains("hidden")) {
        dropdown_content.classList.remove("hidden");
      } else {
        dropdown_content.classList.add("hidden");
      }
    }
    _click_excel_link(event) {
      let excel_link = this._get_excel_link();
      window.open(excel_link);
      let dropdown_content = document.querySelector(`#query-${this.kind}-dropdown`);
      dropdown_content.classList.add("hidden");
    }
    _get_excel_link() {
      return `${this.manager.url_base}${this.manager.engine.cursor.key}/excel/`;
    }
    show_view(on_history) {
      let suffix = `${["result", "questions"].includes(this.kind) ? '' : this.kind}`;
      fetch(`${this.manager.url_base}${this.manager.engine.cursor.key}/${suffix}`, {
        method: "GET",
        headers: {
          "Content-Type": "application/json"
        },
        credentials: "same-origin"
      }).then(response => {
        if (response.ok) {
          response.json().then(data => {
            this.data = data;
            this._set_in_view();
            if (on_history) {
              this.manager.engine._set_url_params(`query-${this.kind}`, data.query.url_code);
            }
          });
        } else {
          console.log(response);
          this.manager.engine.show_view("query-list", false);
        }
      });
    }
    _set_in_view() {
      this.manager._build_sidebar();
      if (this.kind == "result") {
        this._set_summary();
      } else if (this.kind == "questions") {
        this._set_questions();
      } else if (this.kind == "map") {
        this._set_map();
      } else if (this.kind == "data") {
        this._set_datatables();
      }
      this.manager.engine._hide_all_views();
      this.manager.engine.views[`query_${this.kind}`].classList.remove("hidden");
    }
    _set_summary() {
      if (this.charts.summary) {
        this.charts.summary.destroy();
      }
      document.querySelector("#query-result-summary .content").innerHTML = "";
      document.querySelector("#result-summary-chart-labels").innerHTML = "";
      document.querySelector("#result-summary-chart").classList.add("hidden");
      document.querySelector("#query-result .responses-total .total-value").textContent = this.data.total_responses;
      let summary_answer = this._get_first_select_result();
      if (summary_answer) {
        let answer_labels = summary_answer.options.map(x => x.option_name);
        let answer_values = summary_answer.options.map(x => x.total);
        let options = {
          indexAxis: "x"
        };
        let chart = get_chart({
          id: "result-summary-chart",
          type: "bar",
          labels: answer_labels,
          values: answer_values,
          options
        });
        document.querySelector("#result-summary-chart").classList.remove("hidden");
        this.charts.summary = chart;
      }
    }
    _get_first_select_result() {
      let result = null;
      for (let answer_result of this.data.answer_results) {
        if (answer_result.question.kind == "SELECT") {
          result = answer_result;
          break;
        }
      }
      return result;
    }
    _set_questions() {
      document.querySelector("#query-result-questions .content").innerHTML = "";
      let questions_container = document.querySelector("#query-result-questions");
      let content = questions_container.querySelector(".content");
      for (let chart of this.charts.questions) {
        chart.destroy();
      }
      this.charts.questions = [];
      for (let answer_result of this.data.answer_results) {
        let template = questions_container.querySelector("#result-question-template").cloneNode(true);
        template.removeAttribute("id");
        let index = answer_result.question.index;
        template.querySelector(".question-number .value").textContent = index + 1;
        template.querySelector(".question-name").textContent = answer_result.question.name;
        template.querySelector(".responses-total .total-value").textContent = answer_result.total;
        content.appendChild(template);
        if (answer_result.question.kind == "SELECT") {
          let id = `result-question-chart-${index}`;
          let canvas = template.querySelector(".question-chart");
          canvas.setAttribute("id", id);
          let labels = template.querySelector(".chart-labels");
          labels.setAttribute("id", `${id}-labels`);
          let answer_labels = answer_result.options.map(x => x.option_name);
          let answer_values = answer_result.options.map(x => x.total);
          let chart = get_chart({
            id,
            type: "bar",
            labels: answer_labels,
            values: answer_values,
            options: {
              indexAxis: "y"
            }
          });
          this.charts.questions.push(chart);
          canvas.classList.remove("hidden");
          labels.classList.remove("hidden");
        }
        template.classList.remove("hidden");
      }
    }
    _set_map() {
      let map = this._get_map();
      let question_by_uuid = {};
      for (let question of this.data.query.questions) {
        question_by_uuid[question.uuid] = question;
      }
      for (let point_data of this.data.point_list) {
        if (point_data.location) {
          this._set_marker(map, question_by_uuid, point_data);
        }
      }
      this._set_fetch_meta();
    }
    _get_map() {
      if (this.map) {
        this.map.remove();
      }
      document.querySelector("#query-result-map").innerHTML = "";
      let latlng = L.latLng(-33.447869, -70.668423);
      let map = L.map("query-result-map").setView(latlng, 9);
      L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {
        maxZoom: 19
      }).addTo(map);
      map.attributionControl.setPrefix("");
      setTimeout(function () {
        window.dispatchEvent(new Event('resize'));
      }, 100);
      this.map = map;
      return map;
    }
    _set_marker(map, question_by_uuid, point_data) {
      let marker = L.marker([point_data.location.latitude, point_data.location.longitude]).addTo(map);
      let message = "<div class='marker-content'>";
      message += this._set_html_message("Fecha de envío", new Date(point_data.response.send_at).toLocaleString());
      if (point_data.response.email) {
        message += this._set_html_message("Email", point_data.response.email);
      }
      if (point_data.response.rut) {
        message += this._set_html_message("Rut", point_data.response.rut);
      }
      message += this._get_answers_message(point_data, question_by_uuid);
      message += '</div>';
      marker.bindPopup(message);
      if (this.focus == point_data.response.uuid) {
        marker.openPopup();
      }
    }
    _set_html_message(field, value, class_list) {
      return `<div class="item ${class_list ? class_list : ""}"><div class="field">${field}: </div><div class="value">${value}</div></div>`;
    }
    _get_answers_message(point_data, question_by_uuid) {
      let message = "<div class='responses-title'>Respuestas</div><div class='responses-list'>";
      for (let answer of point_data.response.answers) {
        let question = question_by_uuid[answer.question_uuid];
        message += this._set_html_message(`Pregunta ${question.index + 1}`, question.name);
        if (question.kind == "TEXT") {
          message += this._set_html_message("- Texto", answer.text);
        }
        if (question.kind == "IMAGE") {
          message += this._set_html_message("- Imagen", `<img class="image" src="${answer.image}">`);
        }
        if (question.kind == "SELECT") {
          let options = "<div class='options-list'>";
          for (let option of answer.options) {
            options += `<div class="option">${option.name}</div>`;
          }
          options += "</div>";
          message += this._set_html_message("- Opciones", options, "response");
        }
      }
      message += "</div>";
      return message;
    }
    _set_fetch_meta() {
      if (this.data.response_range) {
        let start = new Date(this.data.response_range[0]).toLocaleString();
        let end = new Date(this.data.response_range[1]).toLocaleString();
        let range_responses = `${this.data.point_list.length} respuestas del ${start} al ${end}`;
        document.querySelector("#query-map .range-responses").textContent = range_responses;
      }
      document.querySelector("#query-map .fetch-at").textContent = `Consultado en ${new Date(this.data.fetch_at).toLocaleString()}`;
    }
    _set_datatables() {
      if (this.data_table) {
        this.data_table.destroy();
      }
      let dataset = [];
      for (let item of this.data.dataset) {
        let row = this._get_row_from_item(item);
        dataset.push(row);
      }
      let config = {
        ...this.data.simpletables_config
      };
      config.data.data = dataset;
      config.data.headings = this._get_datables_heading(config);
      this.data_table = new simpleDatatables.DataTable("#query-result-data-table", config);
    }
    _get_row_from_item(item) {
      let row = [];
      for (let i = 0; i < this.data.fields.length; i++) {
        let field = this.data.fields[i];
        let value = item[field];
        if (field == "send_at") {
          let sat = new Date(value);
          let month = sat.getMonth() + 1;
          month = month < 10 ? `0${month}` : month;
          let day = sat.getDate() < 10 ? `0${sat.getDate()}` : sat.getDate();
          value = `${sat.getFullYear()}-${month}-${day} `;
          value += `${sat.getHours()}:${sat.getMinutes()}:${sat.getSeconds()}`;
        }
        if (field == "location" && value) {
          let lat = `<div class="latitude"><span class="label">Latitud: </span><span class="value">${value.latitude}</span></div>`;
          let long = `<div class="latitude"><span class="label">Longitud: </span><span class="value">${value.longitude}</span></div>`;
          value = `${lat}${long}`;
        }
        if (field.includes("pregunta_")) {
          value = this._get_question_value(this.data.query.questions, field, value, item.uuid);
        }
        if (value == null) {
          value = "";
        }
        row.push(value);
      }
      return row;
    }
    _get_datables_heading(config) {
      let headings = [];
      for (let header of config.data.headings) {
        let description = header.desc ? `<div class="dt-field-desc">${header.desc}</div>` : "";
        let heading = `<div class="dt-field"><div class="dt-field-label">${header.label}</div>${description}</div>`;
        headings.push(heading);
      }
      return headings;
    }
    _get_question_value(questions, field, value, response_uuid) {
      let num = parseInt(field.match(/\d+/)[0]);
      let index = num - 1;
      let question = questions[index];
      let tooltip_content = `<div class="tooltip-title"><b>Pregunta ${num}: </b>${question.name}</div>`;
      let final_value = value;
      if (question.kind == "IMAGE" && value) {
        final_value = `<img class="tooltip-image" src="${value}">`;
        tooltip_content += `<a href="${value}" target="_blank">${final_value}</a>`;
      } else if (question.kind == "POINT" && value) {
        let lat = `<div class="latitude"><span class="label">Latitud: </span><span class="value">${value.latitude}</span></div>`;
        let long = `<div class="latitude"><span class="label">Longitud: </span><span class="value">${value.longitude}</span></div>`;
        final_value = `${lat}${long}`;
        tooltip_content += `<div class="link-tabs"><a class="link-tab" href="${this.map_url}?f=${response_uuid}">Ver en mapa</a></div>`;
      } else if (question.kind == "SELECT" && value) {
        final_value = "<ul>";
        for (let opt of value) {
          final_value += `<li>${opt}</li>`;
        }
        final_value += "</ul>";
      }
      return `${final_value}<div class="tooltip">${tooltip_content}</div>`;
    }
  }

  class QueryShareManager {
    constructor({
      manager = null,
      kind = null
    }) {
      this.manager = manager;
      this.data = {};
    }
    show_view(on_history) {
      this.manager._build_sidebar();
      this.manager.engine._hide_all_views();
      this._set_in_view();
      this.manager.engine.views.query_share.classList.remove("hidden");
      if (on_history) {
        this.manager.engine._set_url_params(`query-share`, this.manager.engine.cursor.key);
      }
    }
    _set_in_view() {
      this._click_copy_link = this._click_copy_link.bind(this);
      this._click_download_link = this._click_download_link.bind(this);
      this._click_print_link = this._click_print_link.bind(this);
      let copy_link = document.querySelector("#query-share-copy-link");
      copy_link.addEventListener("click", this._click_copy_link, false);
      let download_link = document.querySelector("#query-share-download-link");
      download_link.addEventListener("click", this._click_download_link, false);
      let print_link = document.querySelector("#query-share-print-link");
      print_link.addEventListener("click", this._click_print_link, false);
    }
    _click_copy_link(event) {
      let submit_link = this._get_submit_link();
      navigator.clipboard.writeText(submit_link);
      let action_container = event.target.closest(".action-container");
      if (!action_container.querySelector(".action-success")) {
        let success = document.createElement("div");
        success.classList.add("action-success");
        success.innerHTML = "<i class='icon ok-simple'></i> Copiado correctamente";
        action_container.appendChild(success);
        setTimeout(function () {
          action_container.querySelector(".action-success").remove();
        }, 3000);
      }
    }
    _click_download_link(event) {
      let pdf_link = this._get_pdf_link();
      window.open(pdf_link + "?k=download");
    }
    _click_print_link(event) {
      let pdf_link = this._get_pdf_link();
      let w = window.open(pdf_link);
      w.print();
    }
    _get_submit_link() {
      return `https://${location.host}/submit/${this.manager.engine.cursor.key}`;
    }
    _get_pdf_link() {
      return `${this.manager.url_base}${this.manager.engine.cursor.key}/share/`;
    }
  }

  class QueryManager {
    constructor({
      engine = null,
      url_base = ""
    }) {
      this.letters = "ABCDEFGHIJKLMNOPQRSTUXYZ";
      this.engine = engine;
      this.url_base = url_base;
      this.list = new QueryListManager({
        manager: this
      });
      this.detail = new QueryDetailManager({
        manager: this
      });
      this.create = new QueryCreateManager({
        manager: this
      });
      this.update = new QueryUpdateManager({
        manager: this
      });
      this.result = new QueryResultManager({
        manager: this,
        kind: "result"
      });
      this.questions = new QueryResultManager({
        manager: this,
        kind: "questions"
      });
      this.map = new QueryResultManager({
        manager: this,
        kind: "map"
      });
      this.data = new QueryResultManager({
        manager: this,
        kind: "data"
      });
      this.share = new QueryShareManager({
        manager: this
      });
      this._click_go_to_view = this._click_go_to_view.bind(this);
    }
    _create_query_item(item, query_item) {
      query_item.querySelector(".name").textContent = item.name;
      query_item.querySelector(".total-responses .value").textContent = item.total_responses;
      if (!item.start_at && !item.end_at) {
        query_item.querySelector(".times").classList.add("hidden");
      } else {
        this._set_times(item, query_item);
      }
      let status_value = query_item.querySelector(".status > .status-value");
      status_value.classList.remove("draft", "finished", "active", "earring");
      status_value.textContent = item.status_verbose.label;
      status_value.classList.add(item.status_verbose.code);
      return query_item;
    }
    _set_times(item, query_item) {
      query_item.querySelector(".times").classList.remove("hidden");
      if (item.start_at) {
        let start_at = new Date(item.start_at).toLocaleString().split(",")[0];
        query_item.querySelector(".start-at").textContent = `Desde: ${start_at}`;
      }
      if (item.end_at) {
        let end_at = new Date(item.end_at).toLocaleString().split(",")[0];
        query_item.querySelector(".end-at").textContent = `Hasta: ${end_at}`;
      }
    }
    _build_sidebar() {
      let current = this.engine.cursor.focus;
      let views_with_sidebar = ["query-detail", "query-update", "query-share"];
      let result_views = ["query-result", "query-data", "query-map", "query-questions"];
      let admin_content = document.querySelector(".admin-content");
      let sidebar = document.querySelector(".admin-content > .sidebar");
      if (!sidebar) {
        sidebar = document.createElement("div");
        sidebar.classList.add("sidebar");
        admin_content.prepend(sidebar);
      } else {
        sidebar.innerHTML = "";
      }
      if ([...result_views, ...views_with_sidebar].includes(current)) {
        sidebar.innerHTML = `
        <div class="sidebar-element${current == 'query-detail' ? ' current' : ''}" to="query-detail">
          Ver consulta
        </div>
        <div class="sidebar-element${result_views.includes(current) ? ' current' : ''}" to="query-result">
          Resultados
        </div>
        <div class="sidebar-element${current == 'query-share' ? ' current' : ''}" to="query-share">
          Compartir
        </div>
        <div class="sidebar-element${current == 'query-update' ? ' current' : ''}" to="query-update">
          Editar
        </div>
      `;
        for (let element of sidebar.querySelectorAll(".sidebar-element")) {
          element.addEventListener("click", this._click_go_to_view, false);
        }
      } else if (current == "query-create") {
        sidebar.innerHTML = `
        <div class="sidebar-element current" to="query-create">
          Crear consulta
        </div>
      `;
      } else {
        sidebar.remove();
      }
    }
    _click_go_to_view(event) {
      let view = event.target.getAttribute("to");
      if (view != this.engine.cursor.focus) {
        this.engine.show_view(view, true);
      }
    }
    get_kind_label(question_data) {
      let kind_label = "";
      if (question_data.kind === "TEXT" && question_data.text_max_length > 150) {
        kind_label = "Texto largo";
      } else if (question_data.kind === "TEXT" && question_data.text_max_length <= 150) {
        kind_label = "Texto corto";
      } else if (question_data.kind === "SELECT") {
        kind_label = "Selección múltiple";
      } else if (question_data.kind === "IMAGE") {
        kind_label = "Imagen";
      } else if (question_data.kind === "POINT") {
        kind_label = "Ubicación";
      }
      return kind_label;
    }
  }

  class AdminEngine {
    constructor({
      url_base = "",
      csrf_token = "",
      focus = null,
      key = null,
      user = null
    }) {
      this.user = user;
      this.csrf_token = csrf_token;
      this.cursor = {
        focus: focus ? focus : "query-list",
        key
      };
      this.url_base = url_base;
      this.ready = this.ready.bind(this);
      this._onpopstate = this._onpopstate.bind(this);
      document.addEventListener("DOMContentLoaded", this.ready);
      this.view_names = ["loading", "query_list", "query_detail", "query_create", "query_update", "query_result", "query_questions", "query_map", "query_data", "query_share"];
      this.views = {};
    }
    ready() {
      this.query_manager = new QueryManager({
        engine: this,
        url_base: this.url_base
      });
      window.addEventListener("popstate", this._onpopstate, false);
      this._set_admin_menu();
      this._set_views();
      this._set_modal();
      this.show_view(this.cursor.focus, true);
    }
    _onpopstate(event) {
      new URLSearchParams(window.location.search);
      this.cursor = event.state;
      this.show_view(this.cursor.focus, false);
    }
    _click_menu_item(event) {
      let focus = event.target.focus;
      this.show_view(focus, true);
      event.target.closest(".menu-content").classList.add("hidden");
    }
    _set_admin_menu() {
      this._click_menu_item = this._click_menu_item.bind(this);
      let menu_button = document.querySelector("#navbar .menu-dropdown .menu-button");
      let menu_content = document.querySelector("#navbar .menu-dropdown .menu-content");
      menu_button.addEventListener("click", event => {
        if (menu_content.classList.contains("hidden")) {
          menu_content.classList.remove("hidden");
        } else {
          menu_content.classList.add("hidden");
        }
      });
      this._set_admin_menu_item("query-create-link", "query-create", menu_content);
      this._set_admin_menu_item("query-list-link", "query-list", menu_content);
    }
    _set_admin_menu_item(id, focus, menu_content) {
      let menu_item = menu_content.querySelector(`#${id}`);
      menu_item.focus = focus;
      for (let child of menu_item.children) {
        child.focus = focus;
      }
      menu_item.addEventListener("click", this._click_menu_item, false);
    }
    _set_views() {
      for (let name of this.view_names) {
        let view = document.querySelector(`#${name.replace("_", "-")}`);
        this.views[name] = view;
      }
    }
    _set_modal() {
      this._click_out_modal_content = this._click_out_modal_content.bind(this);
      let modal = document.querySelector("#admin-modal");
      modal.addEventListener("click", this._click_out_modal_content, false);
    }
    _click_out_modal_content(event) {
      if (event.target.getAttribute("id") === "admin-modal") {
        this.hide_modal();
      }
    }
    _hide_all_views() {
      for (let name in this.views) {
        this.views[name].classList.add("hidden");
      }
    }
    _set_loading() {
      this._hide_all_views();
      this.views.loading.classList.remove("hidden");
    }
    show_view(name, on_history) {
      this._set_loading();
      this.cursor.focus = name;
      let view_name = name.split("-");
      let view_kind = view_name[0];
      let view_selector = view_name[1];
      let manager = null;
      if (view_kind == "query") {
        manager = this.query_manager[view_selector];
      }
      if (manager && manager.show_view) {
        manager.show_view(on_history);
      } else {
        this.cursor.focus = "query-list";
        this.query_manager.list.show_view(on_history);
      }
    }
    _set_url_params(focus, key) {
      let query_params = new URLSearchParams(window.location.search);
      query_params.set("f", focus);
      this.cursor.focus = focus;
      if (key) {
        query_params.set("k", key);
        this.cursor.key = key;
      } else {
        query_params.delete("k");
        this.cursor.key = null;
      }
      history.pushState(this.cursor, null, "?" + query_params.toString());
    }
    show_modal(config) {
      let modal = document.querySelector("#admin-modal");
      let html_element = document.createElement("div");
      html_element.classList.add(config.class);
      html_element.innerHTML = `
      <div class="modal-icon-${config.icon}"></div>
      <div class="modal-title">${config.title}</div>
      <div class="modal-content">${config.content}</div>
      <div class="modal-actions"></div>
    `;
      modal.data = config.data;
      let actions = html_element.querySelector(".modal-actions");
      for (let action of config.actions) {
        let button = document.createElement("div");
        button.classList.add("primary-button");
        button.innerText = action.name;
        button.addEventListener("click", action.click, false);
        actions.appendChild(button);
      }
      modal.querySelector(".admin-modal-content").appendChild(html_element);
      modal.classList.remove("hidden");
    }
    hide_modal() {
      let modal = document.querySelector("#admin-modal");
      modal.classList.add("hidden");
      modal.querySelector(".admin-modal-content").innerHTML = "";
    }
  }

  exports.AdminEngine = AdminEngine;
  exports.QuerySubmitEngine = QuerySubmitEngine;

  return exports;

})({});
//# sourceMappingURL=project.js.map

//# sourceMappingURL=data:application/json;charset=utf-8;base64,{"version":3,"file":"project.js","sources":["static/js/submit/components.js","static/js/submit/geo.js","static/js/submit/images.js","static/js/submit/validations.js","static/js/submit/engine.js","static/js/admin/queries/list.js","static/js/admin/queries/detail.js","static/js/admin/queries/edit.js","static/js/admin/charts.js","static/js/admin/queries/results.js","static/js/admin/queries/share.js","static/js/admin/queries/manager.js","static/js/admin/engine.js"],"sourcesContent":["const focus_names = {\n  entry: \"entry\",\n  identifier: \"identifier\",\n  detail: \"detail\",\n  question: \"question\"\n}\n\nconst suffixes = {\n  cont: \"-container\"\n}\n\nconst button_names = {\n  start: \"start-button\",\n  back: \"back-button\",\n  submit: \"form-submit\",\n}\n\nfunction _get_question_input_list(containers) {\n  let question_list = []\n  for (let i = 0; i < containers.question_list.length; i++) {\n    let question = containers.question_list[i]\n    let question_inputs = question.querySelectorAll(\"input,textarea\")\n    for (let input of question_inputs) {\n      input.question_index = i\n    }\n    question_list.push(Array.from(question_inputs))\n  }\n  return question_list\n}\n\nfunction get_components() {\n  let containers = {\n    entry: document.getElementById(focus_names.entry + suffixes.cont),\n    identifier: document.getElementById(focus_names.identifier + suffixes.cont),\n    detail: document.getElementById(focus_names.detail + suffixes.cont),\n    question_list: Array.from(document.getElementsByClassName(focus_names.question)),\n  }\n  return {\n    navbars: {\n      main: document.getElementById(\"navbar\"),\n      brand: document.getElementById(\"top-brand\"),\n    },\n    containers: containers,\n    buttons: {\n      start: document.getElementById(button_names.start),\n      back: document.getElementById(button_names.back),\n      submit: document.getElementById(button_names.submit),\n    },\n    input_map: {\n      identifier: Array.from(containers.identifier.querySelectorAll(\"input,textarea\")),\n      question_list: _get_question_input_list(containers),\n    },\n  }\n}\n\n\nexport {get_components}\n","\nclass SubmitMapWidget extends MapWidget {\n  constructor (options) {\n    super(options)\n    document.getElementById(options.map_id).style = null;\n    this.map.getView().setCenter(\n      ol.proj.transform([-70.668423, -33.447869], 'EPSG:4326', 'EPSG:3857')\n    )\n    this.interactions.modify.setActive(false)\n    this.map.getView().on(\n      \"change:center\", (event) => {\n        let feature = this.get_feature_marker()\n        if (feature) {\n          let center = this.map.getView().getCenter()\n          let geometry = feature.getGeometry()\n          geometry.setCoordinates(center)\n          this.serializeFeatures()\n        }\n      }\n    )\n    this.featureOverlay.setStyle(new ol.style.Style({\n      image: new ol.style.Icon(/** @type {olx.style.IconOptions} */ ({\n        color: '#8959A8',\n        crossOrigin: 'anonymous',\n        src: options.point_image_url,\n      })),\n    }));\n  }\n  get_feature_marker() {\n    let features = this.featureOverlay.getSource().getFeatures()\n    return features.length > 0 ? features[0]: null\n  }\n\n  createMap() {\n    return new ol.Map({\n        target: this.options.map_id,\n        controls: ol.control.defaults.defaults({attribution: false}),\n        layers: [new ol.layer.Tile({source: new ol.source.OSM()})],\n        view: new ol.View({\n            zoom: this.options.default_zoom\n        })\n    });\n  }\n\n  dispatch_input_event() {\n    document.getElementById(this.options.id).dispatchEvent(new Event(\"input\"))\n  }\n\n  serializeFeatures () {\n    super.serializeFeatures()\n    let feature = this.get_feature_marker()\n    let geometry = feature.getGeometry()\n    this.map.getView().setCenter(geometry.getCoordinates())\n    this.dispatch_input_event()\n  }\n\n  clearFeatures () {\n    super.clearFeatures()\n    this.dispatch_input_event()\n  }\n\n}\n\nfunction set_point_input_event(input) {\n  let map_data = input.parentElement.querySelector(\".map-data\")\n  let options = JSON.parse(map_data.getAttribute(\"data\"))\n  input.mapwidget = new SubmitMapWidget(options);\n}\n\nfunction set_response_geolocation (manager, containers, input_map) {\n  if (\"geolocation\" in navigator) {\n    navigator.geolocation.getCurrentPosition((position) => {\n      manager.user_location = {\n        lon: position.coords.longitude,\n        lat: position.coords.latitude,\n      }\n      let geolocation_input = containers.identifier.querySelector(\"input[name='location']\")\n      geolocation_input.value = `POINT(${manager.user_location.lon} ${manager.user_location.lat})`;\n\n      for (let question_inputs of input_map.question_list) {\n        for (let input of question_inputs) {\n          if (input.mapwidget) {\n            input.mapwidget.map.getView().setCenter(\n              ol.proj.transform(\n                [manager.user_location.lon, manager.user_location.lat],\n                'EPSG:4326',\n                'EPSG:3857',\n              )\n            )\n          }\n        }\n      }\n    })\n  }\n}\n\nexport {\n  set_point_input_event, set_response_geolocation\n}\n","function _show_without_image (input) {\n  let container = input.parentElement\n  container.style.backgroundImage = null\n  container.querySelector(\".image-icon\").classList.remove(\"hidden\")\n  container.querySelector(\".image-icon-description\").classList.remove(\"hidden\")\n  container.querySelector(\".closed-icon\").classList.add(\"hidden\")\n}\n\nfunction _show_with_image (input, url) {\n  let container = input.parentElement\n  container.style.backgroundImage = `url(${url})`\n  container.querySelector(\".image-icon\").classList.add(\"hidden\")\n  container.querySelector(\".image-icon-description\").classList.add(\"hidden\")\n  container.querySelector(\".closed-icon\").classList.remove(\"hidden\")\n}\n\nfunction set_image_preview (input) {\n  _show_without_image(input)\n  let files = input.files\n  let reducer = new window.ImageBlobReduce({\n    pica: window.ImageBlobReduce.pica({ features: [ 'js', 'wasm', 'ww' ] })\n  });\n  if (files.length > 0) {\n    let file = files[0]\n    reducer.toBlob(\n      file, {max: 1000}\n    ).then(\n      blob => {\n        let url = URL.createObjectURL(blob)\n        let reduced_file = new File([blob], input.files[0].name, {type:\"mime/type\", lastModified:new Date().getTime()})\n        let files_container = new DataTransfer()\n        files_container.items.add(reduced_file)\n        _show_with_image(input, url)\n      }\n    ).catch(\n      error => {console.log(error)}\n    )\n  }\n}\n\n\nexport {set_image_preview}\n","import {set_image_preview} from \"./images.js\"\n\n\nfunction validate_rut(input) {\n  let validator = {\n    val: function (rut) {\n      if (!/^[0-9]+[-|‐]{1}[0-9kK]{1}$/.test(rut)) {\n        return false\n      }\n      let tmp   = rut.split('-')\n      let digv  = tmp[1]\n      let _rut   = tmp[0]\n      if (digv == 'K') {digv = 'k'}\n      return (validator.dv(_rut) == digv );\n    },\n    dv: function(T){\n      let M=0, S=1;\n      for(;T;T=Math.floor(T/10))\n        S=(S+T%10*(9-M++%6))%11;\n      return S?S-1:'k';\n    }\n  }\n  if (!input.value || (input.value && validator.val(input.value))) {\n    input.setCustomValidity(\"\")\n  } else {\n    let message = \"Rut inválido\"\n    input.setCustomValidity(message)\n  }\n}\n\nfunction _get_question_errors(question_index, containers) {\n  let errors = containers.question_list[question_index].querySelector(\".errors\")\n  errors.textContent = \"\"\n  return errors\n}\n\n\nfunction validate_image_question(input, report) {\n  let required = input.hasAttribute(\"required\")\n  let question_container = input.parentElement.parentElement.parentElement\n  let errors = question_container.querySelector(\".errors\")\n  let image_input_container = input.parentElement\n  errors.textContent = \"\"\n  image_input_container.classList.remove(\"error\")\n\n  input.setCustomValidity(\"\")\n  if (required && input.files.length == 0) {\n    let message = \"*Este campo es obligatorio\"\n    if (report) {\n      errors.textContent = message\n      image_input_container.classList.add(\"error\")\n    }\n    input.value = \"\"\n    input.setCustomValidity(message)\n  }\n  set_image_preview(input)\n}\n\n\nfunction validate_options_question(input, containers, report) {\n  let field_container =  containers.question_list[input.question_index].querySelector(\"[field='options']\")\n  let maxlength = parseInt(field_container.getAttribute(\"maxlength\"))\n  let required = field_container.hasAttribute(\"required\")\n  let checked_inputs = Array.from(field_container.querySelectorAll(\"input\")).filter(input=>input.checked).length\n  let errors = _get_question_errors(input.question_index, containers)\n\n  input.setCustomValidity(\"\")\n  if (checked_inputs > maxlength && input.checked) {\n    let message = `Seleccione máximo ${maxlength} respuesta${maxlength > 1? 's': ''}`\n    errors.textContent = message\n    input.checked = false\n  }\n  else if (required && checked_inputs == 0 && !input.checked) {\n    let message = `Debe seleccionar al menos una opción`\n    if (report) {errors.textContent = message}\n    input.setCustomValidity(message)\n  }\n  else {\n    for (let i of field_container.querySelectorAll(\"input\")) {\n      i.setCustomValidity(\"\")\n    }\n  }\n  if (input.checked) {\n    input.parentElement.classList.add(\"checked\")\n  } else {\n    input.parentElement.classList.remove(\"checked\")\n  }\n}\n\nfunction validate_point_question (input, containers, report) {\n  let field_container =  containers.question_list[input.question_index].querySelector(\"[field='point']\")\n  let required = field_container.hasAttribute(\"required\")\n  let errors = _get_question_errors(input.question_index, containers)\n  let clear_features = input.parentElement.querySelector(\".clear-features\")\n\n  field_container.classList.remove(\"error\")\n  input.setCustomValidity(\"\")\n  if (input.value) {\n    clear_features.classList.remove(\"hidden\")\n  } else {\n    clear_features.classList.add(\"hidden\")\n  }\n\n  if (required && !input.value) {\n    let message = \"*Este campo es requerido\"\n    if (report) {\n      field_container.classList.add(\"error\")\n      errors.textContent = message\n    }\n    input.setCustomValidity(message)\n  }\n}\n\nfunction validate_text_question (input, containers, report) {\n  let field_container =  input.parentElement\n  let required = field_container.hasAttribute(\"required\")\n  let maxlength = input.getAttribute(\"maxlength\")\n  let minlength = input.getAttribute(\"minlength\")\n  maxlength = Number.isInteger(maxlength) ? maxlength : 255\n  minlength = Number.isInteger(minlength) ? minlength : 1\n  let errors = _get_question_errors(input.question_index, containers)\n\n  field_container.classList.remove(\"error\")\n  input.setCustomValidity(\"\")\n  let valid = true\n  let message = null\n  if (required && !input.value) {\n    message = \"*Este campo es requerido\"\n    valid = false\n  }\n  else if (input.value && input.value.length > maxlength) {\n    message = `*Este campo debe tener como máximo ${maxlength} caracteres`\n    valid = false\n  }\n  else if (input.value && input.value.length < minlength) {\n    message = `*Este campo debe tener como mínimo ${minlength} caracteres`\n    valid = false\n  }\n\n  if (!valid) {\n    if (report) {\n      field_container.classList.add(\"error\")\n      errors.textContent = message\n    }\n    input.setCustomValidity(message)\n  }\n}\n\n\nconst validator = {\n  validate_rut,\n  validate_image_question,\n  validate_options_question,\n  validate_point_question,\n  validate_text_question,\n}\n\nexport {validator}\n","import {\n  get_components\n} from \"./components.js\"\n\nimport {\n  set_point_input_event, set_response_geolocation\n} from \"./geo.js\"\n\nimport {\n  validator\n} from \"./validations.js\"\n\n\nclass QuerySubmitEngine {\n  constructor (\n    {\n      focus = \"entry\",\n      auth_url = \"\",\n      csrf_token = \"\",\n    }\n  ) {\n    this.auth_url = auth_url\n    this.csrf_token = csrf_token\n    this.closed_sk = new URLSearchParams(window.location.search).get(\"k\")\n    this.closed_email = new URLSearchParams(window.location.search).get(\"e\")\n    this.hidden_class_name = \"hidden\";\n    this.comp = get_components()\n    this._set_focus (focus)\n    this._set_event_buttons()\n    this._set_identifier_inputs()\n    this._set_question_inputs()\n    set_response_geolocation(this, this.comp.containers, this.comp.input_map)\n  }\n  _set_focus (focus) {\n    this.focus = !isNaN(focus) ? parseInt(focus): focus\n    this.show_view(this.focus)\n  }\n\n  _set_event_buttons() {\n    this.click_start_button = this.click_start_button.bind(this)\n    this.comp.buttons.start.addEventListener(\"click\", this.click_start_button, false)\n\n    this.click_next_button = this.click_next_button.bind(this)\n    this.comp.buttons.submit.addEventListener(\"click\", this.click_next_button, false)\n\n    this.show_back_form = this.show_back_form.bind(this)\n    this.comp.buttons.back.addEventListener(\"click\", this.show_back_form, false)\n  }\n\n  _set_identifier_inputs () {\n    this.change_identifier_input = this.change_identifier_input.bind(this)\n    for (let input of this.comp.input_map.identifier) {\n      if (this.closed_email && input.getAttribute(\"name\") == \"email\") {\n        input.value = this.closed_email\n        input.setAttribute(\"disabled\", true)\n      }\n      input.addEventListener(\"input\", this.change_identifier_input, false)\n    }\n  }\n\n  _set_question_inputs() {\n    this.change_question_input = this.change_question_input.bind(this)\n    this.click_image_clear = this.click_image_clear.bind(this)\n    for (let inputs of this.comp.input_map.question_list) {\n      for (let input of inputs) {\n        input.addEventListener(\"input\", this.change_question_input, false)\n        if (input.type == \"checkbox\") {\n          validator.validate_options_question(input, this.comp.containers, false)\n        }\n        if (input.classList.contains(\"vSerializedField\")) {\n          set_point_input_event(input)\n          validator.validate_point_question(input, this.comp.containers, false)\n        }\n        if (input.type == \"file\") {\n          let input_container = input.parentElement\n          let input_close_icon = input_container.querySelector(\".closed-icon\")\n          input_close_icon.addEventListener(\"click\", this.click_image_clear, false)\n        }\n        if (input.parentElement.getAttribute(\"field\") == \"text\") {\n          validator.validate_text_question(input, this.comp.containers, false)\n        }\n      }\n    }\n  }\n\n  click_start_button (event) {\n    this.show_view(\"identifier\")\n  }\n\n  set_loading () {\n    this.hide_all()\n    this.comp.navbars.main.classList.remove(\"hidden\")\n    document.querySelector(\".load.content-container\").classList.remove(\"hidden\")\n  }\n\n  identify() {\n    let identifier_data = {}\n    for (let input of this.comp.input_map.identifier) {\n      let field = input.getAttribute(\"name\")\n      if (field == \"rut\") {\n        identifier_data.rut = input.value\n      } else if (field == \"email\") {\n        identifier_data.email = input.value\n      }\n    }\n    if (this.closed_sk) {\n      identifier_data.sk = this.closed_sk\n    }\n    fetch(this.auth_url, {\n      method: \"POST\",\n      body: JSON.stringify(identifier_data),\n      headers: {\"Content-Type\": \"application/json\",  \"X-CSRFToken\": this.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.status == 200) {\n        this.show_view(\"detail\")\n      } else {\n        response.json().then((data)=> {\n          let errors = this.comp.containers.identifier.querySelector(\".errors\")\n          if (data.email) {errors.textContent = data.email}\n          if (data.rut) {errors.textContent = data.rut}\n          this.show_view(\"identifier\")\n        })\n      }\n    })\n  }\n\n  click_next_button (event) {\n    let total_questions = this.comp.containers.question_list.length\n    let valid = event.currentTarget.getAttribute(\"disabled\") != \"true\"\n    if (valid) {\n      if (this.focus != total_questions - 1) {\n        event.preventDefault()\n      } else {\n        for (let input of this.comp.input_map.identifier) {\n          if (this.closed_email && input.getAttribute(\"name\") == \"email\") {\n            input.removeAttribute(\"disabled\")\n          }\n        }\n        this.set_loading()\n      }\n      if (this.focus == \"identifier\") {\n        this.set_loading()\n        this.identify()\n      } else if (this.focus == \"detail\") {\n        this.show_view(0)\n      }\n      else if (Number.isInteger(this.focus)) {\n        if (this.focus < total_questions - 1) {\n          this.show_view(this.focus + 1)\n        }\n      }\n    }\n  }\n\n  change_identifier_input (event) {\n    let input = event.currentTarget\n    let button = this.comp.buttons.submit\n    let errors = input.parentElement.parentElement.querySelector(\".errors\")\n    let valid = true\n    for (let input of this.comp.input_map.identifier) {\n      if (input.getAttribute(\"name\") == \"rut\") {\n        validator.validate_rut(input)\n      }\n      valid &&= input.validity.valid\n    }\n    if (valid) {\n      errors.textContent = \"\"\n    } else {\n      errors.textContent = \"*Error de autenticación\"\n    }\n    this.set_next_button_status(\"identifier\", true)\n  }\n\n  change_question_input (event) {\n    let input = event.currentTarget\n    this.validate_input(input, true)\n    this.set_next_button_status(input.question_index, true)\n  }\n\n  validate_input (input, report) {\n    if (input.type == \"file\") {\n      validator.validate_image_question(input, report)\n    }\n    if (input.type == \"checkbox\") {\n      validator.validate_options_question(input, this.comp.containers, report)\n    }\n    if (input.classList.contains(\"vSerializedField\")) {\n      validator.validate_point_question(input, this.comp.containers, report)\n    }\n    if (input.parentElement.getAttribute(\"field\") == \"text\") {\n      validator.validate_text_question(input, this.comp.containers, report)\n    }\n  }\n\n  click_image_clear(event) {\n    let input_container = event.currentTarget.parentElement\n    let input = input_container.querySelector(\"input\")\n    input.value = \"\"\n    validator.validate_image_question(input, true)\n    this.set_next_button_status(input.question_index, true)\n  }\n\n  hide_all () {\n    this.comp.navbars.main.classList.add(this.hidden_class_name)\n    this.comp.navbars.brand.classList.add(this.hidden_class_name)\n    this.comp.containers.entry.classList.add(this.hidden_class_name)\n    this.comp.containers.identifier.classList.add(this.hidden_class_name)\n    this.comp.containers.detail.classList.add(this.hidden_class_name)\n    for (let question of this.comp.containers.question_list) {\n        question.classList.add(this.hidden_class_name)\n    }\n    this.comp.buttons.submit.classList.add(this.hidden_class_name)\n    this.comp.buttons.back.classList.add(this.hidden_class_name)\n    document.querySelector(\".load.content-container\").classList.add(this.hidden_class_name)\n  }\n\n  show_view(focus) {\n    this.hide_all()\n    this.focus = focus\n    if (focus != \"entry\") {\n      this.comp.buttons.back.classList.remove(this.hidden_class_name)\n      this.comp.buttons.submit.classList.remove(this.hidden_class_name)\n      this.comp.navbars.main.classList.remove(this.hidden_class_name)\n    } else {\n      this.comp.navbars.brand.classList.remove(this.hidden_class_name)\n    }\n    if (Number.isInteger(focus)) {\n      for (let input of this.comp.input_map.question_list[focus]) {\n        this.validate_input(input, false)\n      }\n      this.set_next_button_status(focus)\n      this.comp.containers.question_list[focus].classList.remove(this.hidden_class_name)\n    } else {\n      this.comp.containers[focus].classList.remove(this.hidden_class_name)\n      this.comp.buttons.submit.removeAttribute(\"disabled\")\n    }\n    if (focus == \"identifier\") {\n      this.set_next_button_status(focus)\n    }\n  }\n\n  show_back_form () {\n    if (this.focus == \"identifier\") {\n        this.show_view(\"entry\")\n    }\n    else if (this.focus == \"detail\") {\n      this.show_view(\"identifier\")\n    }\n    else if (!isNaN(this.focus)) {\n        if (this.focus == 0) {this.show_view(\"detail\")}\n        else {this.show_view(this.focus - 1)}\n    }\n  }\n\n  set_next_button_status(focus, report) {\n    let next_button = this.comp.buttons.submit\n    let valid = true\n    let input_list = !isNaN(this.focus)? this.comp.input_map.question_list[focus]: this.comp.input_map.identifier\n    for (let input of input_list) {\n      valid &&= input.validity.valid\n    }\n    if (valid) {\n      next_button.removeAttribute(\"disabled\")\n    } else {\n      next_button.setAttribute(\"disabled\", true)\n    }\n  }\n}\n\nexport {QuerySubmitEngine}\n","class QueryListManager {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.data = []\n    this._click_query_detail = this._click_query_detail.bind(this)\n  }\n\n  show_view(on_history) {\n    fetch (this.manager.url_base, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data.list\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-list\", null)\n          }\n        })\n      } else {\n        console.log(response)\n      }\n    })\n  }\n\n  _set_in_view() {\n    let template = document.querySelector(\"#query-item-template\").cloneNode(true)\n    template.classList.remove(\"hidden\")\n    let query_list = this.manager.engine.views.query_list.querySelector(\".query-item-list\")\n    query_list.innerHTML = \"\"\n    for (let item of this.data) {\n      let query_item = template.cloneNode(true)\n      let returned_query_item = this.manager._create_query_item(item, query_item)\n      let detail_link = returned_query_item.querySelector(\".action-button.item-detail-link\")\n      detail_link.query_uuid = item.uuid\n      detail_link.addEventListener(\n        \"click\", this._click_query_detail, false\n      )\n      if (this.manager.engine.user.is_superuser && item.created_by_email) {\n        let email = document.createElement(\"div\")\n        email.classList.add(\"query-item-created-by\")\n        email.textContent = item.created_by_email\n        returned_query_item.appendChild(email)\n      }\n      query_list.appendChild(returned_query_item)\n    }\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_list.classList.remove(\"hidden\")\n  }\n\n  _click_query_detail (event) {\n    this.manager.engine.cursor.key = event.currentTarget.query_uuid\n    this.manager.engine.show_view(\"query-detail\", true)\n  }\n\n}\n\nexport {QueryListManager}\n","class QueryDetailManager {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.data = {}\n    this.charts = {\n      summary: null\n    }\n    this._click_query_edit = this._click_query_edit.bind(this)\n  }\n\n  show_view(on_history) {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-detail\", data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  _set_in_view () {\n    let query_item = document.querySelector(\"#query-detail-item\")\n    let returned_query_item = this.manager._create_query_item(this.data.query, query_item)\n    if (this.data.query.is_active) {\n      document.querySelector(\"#detail-action-submit\").setAttribute(\"href\", this.data.links.submit)\n      document.querySelector(\"#detail-action-submit\").classList.remove(\"hidden\")\n    } else {\n      document.querySelector(\"#detail-action-submit\").classList.add(\"hidden\")\n    }\n    this._set_query_preview()\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_detail.classList.remove(\"hidden\")\n  }\n\n  _click_query_edit (event) {\n    this.manager.engine.show_view(\"query-update\", true)\n  }\n\n  _set_query_preview () {\n    document.querySelector(\"#query-detail .query-preview-description\").textContent = this.data.query.description\n    let questions = document.querySelector(\"#query-detail .query-preview-questions\")\n    questions.innerHTML = \"\"\n    let index = 0\n    for (let answer_result of this.data.answer_results) {\n      let question = answer_result.question\n      let question_container = document.createElement(\"div\")\n      question_container.classList.add(\"question-container\")\n      question_container.innerHTML = `\n        <div class=\"subtitle\">Pregunta ${index + 1}</div>\n        <div class=\"question-item-kind\">${this.manager.get_kind_label(question)}</div>\n        <div class=\"question-name\">${question.name}</div>\n        <div class=\"question-description\">${question.description? question.description: \"\"}</div>\n      `\n      if (question.kind == \"POINT\") {\n        question_container.innerHTML += \"<div class='question-map map-bg'></div>\"\n      } else if (question.kind == \"SELECT\") {\n        question_container.innerHTML += `<div class=\"question-options\"></div>`\n        let options_container = question_container.querySelector(\".question-options\")\n        let option_index = 0\n        for (let option of question.options) {\n          options_container.innerHTML += `\n            <div class=\"option\">\n              <span class=\"option-label\">${this.manager.letters[option_index]}.</span>\n              <span class=\"option-value\">${option.name}</span>\n            </div>\n          `\n          option_index += 1\n        }\n      }\n      questions.appendChild(question_container)\n      index += 1\n    }\n  }\n}\n\nexport {QueryDetailManager}\n","class QueryEditBase {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.required_fields = [\"name\"]\n    this.data = this._get_default_data()\n    this.inputs = {}\n    this.errors = {}\n    this.buttons = {}\n    this.can_edit_questions = true\n\n    this._click_publish = this._click_publish.bind(this)\n    this._dropdown_create_question = this._dropdown_create_question.bind(this)\n    this._click_create_question = this._click_create_question.bind(this)\n    this._move_question_ondragstart = this._move_question_ondragstart.bind(this)\n    this._move_question_ondragend = this._move_question_ondragend.bind(this)\n    this._move_question_ondrop = this._move_question_ondrop.bind(this)\n    this._click_remove_question = this._click_remove_question.bind(this)\n\n    this._click_question_add_option = this._click_question_add_option.bind(this)\n    this._click_question_max_answers_menu = this._click_question_max_answers_menu.bind(this)\n    this._click_question_max_answers_set = this._click_question_max_answers_set.bind(this)\n    this._click_question_remove_option = this._click_question_remove_option.bind(this)\n    this._set_initial()\n    this._set_publish_button()\n    this._set_create_question_button()\n    this._set_query_inputs()\n  }\n\n  _get_default_data () {\n    return {\n        name: null,\n        description: null,\n        start_at: null,\n        end_at: null,\n        active: true,\n        questions: [],\n        auth_rut: \"OPTIONAL\",\n        auth_email: \"OPTIONAL\",\n    }\n  }\n\n  _set_initial() {}\n\n  _set_publish_button () {\n    let publish = document.querySelector(`#${this.view_type}-query-button`)\n    publish.disabled = true\n    publish.classList.add(\"disabled\")\n    publish.addEventListener(\"click\", this._click_publish, false)\n    this.buttons.publish = publish\n  }\n\n  _click_publish(event) {\n    let publish = document.querySelector(`#${this.view_type}-query-button`)\n    if (publish.disabled == false) {\n      this.manager.engine._set_loading()\n      this.execute_service()\n    }\n  }\n\n  execute_service () {}\n\n  _clean_data() {\n    this.data = this._get_default_data()\n    this._build_question_from_data()\n    for (let field in this.inputs) {\n      let input = this.inputs[field]\n      if ([\"start_at\", \"end_at\"].includes(field) && this.data[field]) {\n        input.value = new Date(this.data[field]).toISOString().split('T')[0]\n      } else {\n        input.value = this.data[field]\n      }\n    }\n    this.validate_inputs()\n  }\n\n  _set_query_inputs() {\n    let name = document.querySelector(`#query-${this.view_type}-name`)\n    let description = document.querySelector(`#query-${this.view_type}-description`)\n    let start_at = document.querySelector(`#query-${this.view_type}-start_at`)\n    let end_at = document.querySelector(`#query-${this.view_type}-end_at`)\n    let active = document.querySelector(`#query-${this.view_type}-active`)\n    let auth_email = document.querySelector(`#query-${this.view_type}-auth-email`)\n    let auth_rut = document.querySelector(`#query-${this.view_type}-auth-rut`)\n    this._change_input = this._change_input.bind(this)\n    for (let input of [name, description, start_at, end_at, active, auth_email, auth_rut]) {\n      input.field = input.getAttribute(\"field\")\n      input.addEventListener(\"input\", this._change_input, false)\n      this.inputs[input.field] = input\n    }\n    this.error_containers = {}\n    for (let field in this.data) {\n      if (field != \"questions\") {\n        let container = document.querySelector(`#query-${this.view_type}-${field}-error`)\n        if (container) {\n          this.error_containers[field] = container\n        }\n      }\n    }\n    this.error_containers[\"times\"] = document.querySelector(`#query-${this.view_type}-times-error`)\n  }\n\n  _set_errors_message() {\n    for (let field in this.error_containers) {\n      if (field != \"questions\") {\n        this.error_containers[field].innerText = \"\"\n      } else {\n        for (let index in this.error_containers[field]) {\n          for (let question_field in this.error_containers[field][index]) {\n            this.error_containers[field][index][question_field].innerText = \"\"\n          }\n        }\n      }\n    }\n    for (let field in this.errors) {\n      if (![\"questions\", \"start_at\", \"end_at\"].includes(field)) {\n        this.error_containers[field].innerText = this.errors[field]\n      } else if ([\"start_at\", \"end_at\"].includes(field)) {\n        this.error_containers.times.innerText = this.errors[field]\n      } else if (typeof this.errors[field] == \"object\") {\n        for (let index in this.errors[field]) {\n          for (let question_field in this.errors[field][index]) {\n            this.error_containers[field][parseInt(index)][question_field].innerText = this.errors[field][index][question_field]\n          }\n        }\n      }\n    }\n  }\n\n  _change_input (event) {\n    let field = event.target.field\n    let value = event.target.value != \"\"? event.target.value: null\n    if (event.target.question) {\n      if (field == \"required\") {\n        value = event.target.checked? true: false\n      }\n      if (field == \"question-option\") {\n        this.data.questions[event.target.index].options[event.target.option_index].name = value\n      } else {\n        this.data.questions[event.target.index][field] = value\n      }\n    } else {\n      this.data[field] = value\n    }\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  validate_inputs() {\n    this.errors = {}\n    let no_question_message = \"Debe crear al menos una pregunta\"\n    if (this.data.questions.length == 0) {\n      this.errors.questions = no_question_message\n    } else {\n      delete this.errors.questions\n    }\n    for (let field in this.data) {\n      if (field == \"questions\") {\n        for (let question of this.data.questions) {\n          for (let field in question) {\n            let value = question[field]\n            this._val_field_value_is_required(field, value, question.order)\n          }\n          if (question.kind == \"SELECT\") {\n            this._val_question_options(question)\n          }\n        }\n      } else {\n        let value = this.data[field]\n        this._val_field_value_is_required(field, value)\n        if (value && [\"start_at\", \"end_at\"].includes(field)) {\n          this._val_date_field_value(field, value)\n        }\n      }\n    }\n    if (this.errors.questions && this.errors.questions.length == 0) {\n      delete this.errors.questions\n    }\n    if (this.errors.questions && this.errors.questions != no_question_message) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    } else {\n      this.buttons.new_question.disabled = false\n      this.buttons.new_question.classList.remove(\"disabled\")\n    }\n    if (!this.can_edit_questions) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    }\n    if (\n      Object.keys(this.errors).length === 0\n      && this.errors.constructor === Object\n    ) {\n      this.buttons.publish.classList.remove(\"disabled\")\n      this.buttons.publish.disabled = false\n    } else {\n      this.buttons.publish.classList.add(\"disabled\")\n      this.buttons.publish.disabled = true\n    }\n  }\n\n  _val_date_field_value(field, value) {\n    let start_at = this.data[\"start_at\"]? new Date(this.data[\"start_at\"]): null\n    let end_at = this.data[\"end_at\"]? new Date(this.data[\"end_at\"]): null\n    if (start_at && end_at && start_at >= end_at) {\n      let message = \"La fecha de inicio debe ser menor que la de término\"\n      this._set_field_error(field, message)\n    } else {\n      this._clean_field_error(\"start_at\")\n    }\n  }\n\n  _val_field_value_is_required(field, value, question_index) {\n    if (this.required_fields.includes(field) && (!value || value.trim() == \"\")) {\n      let message = \"Este campo es requerido\"\n      this._set_field_error(field, message, question_index)\n    } else {\n      this._clean_field_error(field, question_index)\n    }\n  }\n\n  _val_question_options(question) {\n    let message = \"Debe agregar al menos dos opciones y no pueden estar vacías\"\n    if (question.options.length < 2) {\n      this._set_field_error(\"options\", message, question.order)\n    }\n    let option_values = []\n    for (let option of question.options) {\n      if (!option.name || option.name.trim() == \"\") {\n        this._set_field_error(\"options\", message, question.order)\n        break\n      }\n      if (option_values.includes(option.name)) {\n        message = \"Las opciones no pueden ser iguales\"\n        this._set_field_error(\"options\", message, question.order)\n        break\n      }\n      option_values.push(option.name)\n    }\n  }\n\n  _set_field_error (field, message, question_index) {\n    if (!isNaN(question_index)) {\n      if (!this.errors.questions) {\n        this.errors.questions = {}\n      }\n      if (!this.errors.questions[question_index]) {\n        this.errors.questions[question_index] = {}\n      }\n      this.errors.questions[question_index][field] = message\n    } else {\n      this.errors[field] = message\n    }\n  }\n\n  _clean_field_error (field, question_index) {\n    if (!isNaN(question_index) && this.errors.questions && this.errors.questions[question_index]) {\n      delete this.errors.questions[question_index][field]\n    }\n    if (isNaN(question_index)) {\n      delete this.errors[field]\n    }\n  }\n\n  _set_create_question_button() {\n    let button = document.querySelector(`#query-${this.view_type}-create-question-button`)\n    button.addEventListener(\"click\", this._dropdown_create_question, false)\n    button.disabled = false\n    this.buttons.new_question = button\n    let kinds = Array.from(document.querySelectorAll(`#query-${this.view_type}-create-question-kinds .dropdown-item`))\n    for (let kind of kinds) {\n      kind.kind = kind.getAttribute(\"kind\")\n      kind.type = kind.getAttribute(\"type\")\n      kind.addEventListener(\"click\", this._click_create_question, false)\n    }\n  }\n\n  _dropdown_create_question(event) {\n    let button = document.querySelector(`#query-${this.view_type}-create-question-button`)\n    if (this.can_edit_questions) {\n      let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`)\n      if (!button.disabled) {\n        if (dropdown.classList.contains(\"hidden\")) {\n          dropdown.classList.remove(\"hidden\")\n        } else {\n          dropdown.classList.add(\"hidden\")\n        }\n      }\n    }\n  }\n\n  _click_create_question (event) {\n    let question = {\n      kind: event.target.kind,\n      name: null, description: null,\n      required: false,\n      order: this.data.questions.length,\n    }\n    if (event.target.kind === \"TEXT\") {\n      if (event.target.type == \"large\") {\n        question.text_max_length = 400\n      } else {\n        question.text_max_length = 150\n      }\n    } else if (event.target.kind == \"SELECT\") {\n      question.options = []\n    }\n    this.data.questions.push(question)\n    this._build_question_from_data()\n    let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`)\n    dropdown.classList.add(\"hidden\")\n    document.querySelector(`#query-${this.view_type}-questions-tab .question-item:last-child`).scrollIntoView()\n  }\n\n  _build_question_from_data() {\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    questions_container.innerHTML = \"\"\n    let index = 0\n    for (let question_data of this.data.questions) {\n      let question = this._create_question_element(question_data, index)\n      questions_container.appendChild(question)\n      let delete_button = question.querySelector(\".action-delete\")\n      this._prepare_question_inputs(question, question_data, [\"name\", \"description\", \"required\"])\n      if (this.can_edit_questions) {\n        let click_delete = this._get_question_delete_callback()\n        delete_button.addEventListener(\"click\", click_delete, false)\n        this._set_question_draggable(question)\n        this._set_question_error_containers(question)\n      } else {\n        delete_button.remove()\n        this._set_disable_edit_questions(question)\n      }\n      index += 1\n    }\n    this.validate_inputs()\n  }\n\n  _get_question_delete_callback() {\n    return this._click_remove_question\n  }\n\n  _get_question_id(index) { return `query-${this.view_type}-question-item-${index}` }\n\n  _create_question_element(question_data, index) {\n    let question_id = this._get_question_id(index)\n    var question = document.createElement(\"div\")\n    question.classList.add(\"question-item\")\n    question.index = index\n    question.setAttribute(\"id\", question_id)\n    question.kind = question_data.kind\n    let kind_label = this.manager.get_kind_label(question_data)\n    question.innerHTML = `\n      <div class=\"question-move-previous\"></div>\n      <div class=\"question-container\">\n        <div class=\"question-item-move\">\n          <i class=\"icon move\"></i>\n        </div>\n        <div class=\"question-item-content\">\n          <div class=\"question-item-kind\">${kind_label}</div>\n          <input class=\"question-item-name\"\n                 id=\"query-${this.view_type}-${question_id}-name-input\"\n                 type=\"text\"\n                 field=\"name\"\n                 placeholder=\"Escribe tu pregunta aquí\">\n          </input>\n          <div class=\"error-label\" id=\"query-${this.view_type}-question-${index}-name-error\"></div>\n          <input class=\"question-item-description\"\n                 id=\"query-${this.view_type}-${question_id}-description-input\"\n                 type=\"text\"\n                 field=\"description\"\n                 placeholder=\"Agrega una descripción para esta pregunta (opcional)\">\n          </input>\n          <div class=\"error-label\" id=\"query-${this.view_type}-question-${index}-description-error\"></div>\n        </div>\n        <div class=\"question-item-actions\">\n          <div class=\"actions-top\">\n            <div class=\"action-delete\"><i class=\"icon close-dark\"></i></div>\n          </div>\n          <div class=\"actions-bottom\">\n            <div class=\"action-required\">\n              <label class=\"action-checkbox\">\n                <div class=\"action-label\">Obligatorio</div>\n                <input type=\"checkbox\"\n                       id=\"query-${this.view_type}-${question_id}-required-input\"\n                       field=\"required\"\n                       class=\"action-checkbox-input\">\n                </input>\n                <span class=\"action-checkbox-checkmarker\"></span>\n              </label>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"question-move-next\"></div>\n    `\n    let question_content = question.querySelector(\".question-item-content\")\n    if (question_data.kind === \"TEXT\") {\n      let type = question_data.text_max_length > 150 ? \"largo\": \"corto\"\n      question_content.innerHTML += `<div class=\"kind-text\">Respuesta de texto ${type} (${question_data.text_max_length} caracteres)</div>`\n    } else if (question_data.kind === \"IMAGE\") {\n      question_content.innerHTML += `<div class=\"kind-image\">Respuesta de imagen o foto</div>`\n    } else if (question_data.kind === \"POINT\") {\n      question_content.innerHTML += `<div class=\"kind-point\"></div>`\n    } else if (question_data.kind === \"SELECT\") {\n      this._set_question_options(question, question_data)\n      this._set_question_max_answers(question, question_data)\n    }\n    return question\n  }\n\n  _prepare_question_inputs(question, question_data, fields) {\n    let question_id = this._get_question_id(question.index)\n    for (let field of fields) {\n      let element = question.querySelector(`#query-${this.view_type}-${question_id}-${field}-input`)\n      element.field = field\n      element.index = question.index\n      element.question = true\n      if (field === \"required\") {\n        element.checked = question_data[field]\n      } else {\n        element.value = question_data[field]\n      }\n      if (this.can_edit_questions) {\n        element.addEventListener(\"input\", this._change_input, false)\n      } else {\n        element.setAttribute(\"disabled\", true)\n      }\n    }\n  }\n\n  _set_question_error_containers (question) {\n    let base_id = \"query-create\"\n    if (!this.error_containers.questions) {\n      this.error_containers.questions = {}\n    }\n    if (!this.error_containers.questions[question.index]) {\n      this.error_containers.questions[question.index] = {}\n    }\n    let fields = [\"name\", \"description\"]\n    if (question.kind == \"SELECT\") {\n      fields.push(\"options\")\n    }\n    for (let field of fields) {\n      this.error_containers.questions[question.index][field] = question.querySelector(\n        `#query-${this.view_type}-question-${question.index}-${field}-error`\n      )\n    }\n  }\n\n  _set_disable_edit_questions (question) {\n    for (let input of question.querySelectorAll(\"input\")) {\n      input.setAttribute(\"disabled\", true)\n    }\n  }\n\n  _click_remove_question(event) {\n    let question = event.target.closest(\".question-item\")\n    this.data.questions.splice(question.index, 1)\n    this._build_question_from_data()\n  }\n\n  _set_question_options (question, question_data) {\n    let question_content = question.querySelector(\".question-item-content\")\n    let options_container = document.createElement(\"div\")\n    options_container.classList.add(\".question-options-container\")\n    options_container.innerHTML = `\n      <div class=\"question-option-list\"></div>\n      <div class=\"error-label\" id=\"query-${this.view_type}-question-${question.index}-options-error\"></div>\n      <div class=\"question-option-add\">+ Agregar opción</div>\n    `\n    let question_add_button = options_container.querySelector(\".question-option-add\")\n    question_add_button.index = question.index\n    question_add_button.addEventListener(\"click\", this._click_question_add_option, false)\n    question_content.appendChild(options_container)\n    let option_list = options_container.querySelector(`.question-option-list`)\n    let option_index = 0\n    for (let option_data of this.data.questions[question.index].options) {\n      let option = document.createElement(\"div\")\n      option.classList.add(\"question-option\")\n      let option_id = `query-${this.view_type}-question-option-${question.index}-${option_index}`\n      option.innerHTML = `\n        <div class=\"question-option-label\">${this.manager.letters[option_index]}.</div>\n        <input id=\"${option_id}\" type=\"text\" class=\"question-option-input\" placeholder=\"Opción ${option_index + 1}\">\n        <div class=\"question-option-delete\">X</div>\n      `\n      let input = option.querySelector(\".question-option-input\")\n      input.field = \"question-option\"\n      input.index = question.index\n      input.question = true\n      input.option_index = option_index\n      input.value = option_data.name\n      input.addEventListener(\"input\", this._change_input, false)\n      let delete_button = option.querySelector(\".question-option-delete\")\n      if (this.can_edit_questions) {\n        delete_button.option_index = option_index\n        delete_button.addEventListener(\"click\", this._click_question_remove_option, false)\n      } else {\n        delete_button.remove()\n      }\n      option_index += 1\n      option_list.appendChild(option)\n    }\n  }\n\n  _click_question_remove_option(event) {\n    let question = event.target.closest(\".question-item\")\n    this.data.questions[question.index].options.splice(event.target.option_index, 1)\n    this._build_question_from_data()\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  _set_question_max_answers (question, question_data) {\n    let actions = question.querySelector(\".question-item-actions .actions-bottom\")\n    actions.innerHTML = `\n      <div class=\"action-max-answers\">\n        <div class=\"action-max-answers-button\">\n          <span class=\"action-label\">Cantidad de respuestas</span> <i class=\"icon bottom\"></i>\n        </div>\n        <div class=\"action-max-answers-dropdown hidden\"></div>\n      </div>\n    ` + actions.innerHTML\n    let button = actions.querySelector(\".action-max-answers-button\")\n    button.addEventListener(\"click\", this._click_question_max_answers_menu, false)\n    let dropdown = actions.querySelector(\".action-max-answers-dropdown\")\n    for (let i = 0; i < 5; i++) {\n      let option = document.createElement(\"div\")\n      option.classList.add(\"action-max-answers-option\")\n      option.value = i + 1\n      let message = `${i + 1} respuesta`\n      if (option.value == this.data.questions[question.index].max_answers) {\n        actions.querySelector(\".action-label\").innerText = message\n      }\n      if (i > 0) { message += \"s\" }\n      option.innerText = message\n      option.addEventListener(\"click\", this._click_question_max_answers_set, false)\n      dropdown.appendChild(option)\n    }\n  }\n\n  _click_question_add_option (event) {\n    let question = event.target.closest(\".question-item\")\n    let order = this.data.questions[question.index].options.length\n    let empty_option = {\n      name: null, order: order\n    }\n    this.data.questions[question.index].options.push(empty_option)\n    this._build_question_from_data()\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  _click_question_max_answers_menu(event) {\n    let question = event.target.closest(\".question-item\")\n    let dropdown = question.querySelector(\".action-max-answers-dropdown\")\n    if (this.can_edit_questions) {\n      if (dropdown.classList.contains(\"hidden\")) {\n        dropdown.classList.remove(\"hidden\")\n      } else {\n        dropdown.classList.add(\"hidden\")\n      }\n    }\n  }\n\n  _click_question_max_answers_set (event) {\n    let question = event.target.closest(\".question-item\")\n    let button_label = question.querySelector(\".action-max-answers .action-label\")\n    let dropdown = question.querySelector(\".action-max-answers-dropdown\")\n    this.data.questions[question.index].max_answers = event.target.value\n    button_label.innerText = event.target.innerText\n    dropdown.classList.add(\"hidden\")\n  }\n\n  _set_question_draggable (question) {\n    let container = question.querySelector(\".question-container\")\n    container.draggable = true\n    container.ondragstart = this._move_question_ondragstart\n    container.ondragend = this._move_question_ondragend\n    let move_previous = question.querySelector(\".question-move-previous\")\n    let move_next = question.querySelector(\".question-move-next\")\n    move_previous.ondragenter = () => move_previous.classList.add(\"active\")\n    move_previous.ondragleave = () => move_previous.classList.remove(\"active\")\n    move_next.ondragenter = () => move_next.classList.add(\"active\")\n    move_next.ondragleave = () => move_next.classList.remove(\"active\")\n    move_previous.ondragover = (event) => event.preventDefault()\n    move_previous.ondrop = this._move_question_ondrop\n    move_previous.kind = \"previous\"\n    move_next.ondragover = (event) => event.preventDefault()\n    move_next.kind = \"next\"\n    move_next.ondrop = this._move_question_ondrop\n  }\n\n  _move_question_ondragstart(event) {\n    let question = event.target.closest(\".question-item\")\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    this.current_pos = question.index\n    setTimeout(()=> { question.style.display = \"none\"}, 0)\n    questions_container.style.heigth = questions_container.clientHeigth - question.clientHeigth + \"px\"\n  }\n\n  _move_question_ondragend (event) {\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    for (let question of questions_container.children) {\n      question.style.display = \"flex\"\n      question.querySelector(\".question-move-previous\").classList.remove(\"active\")\n      question.querySelector(\".question-move-next\").classList.remove(\"active\")\n    }\n  }\n\n  _move_question_ondrop(event) {\n    event.preventDefault()\n    let question = event.target.closest(\".question-item\")\n    let kind = event.target.kind\n    let total_questions = this.data.questions.length\n    let to_index = null\n    if (kind == \"previous\") {\n      to_index = question.index - 1 < 0? 0 : question.index\n    }\n\n    else if (kind == \"next\") {\n      to_index = question.index\n    }\n    if (this.current_pos === to_index) {\n      return\n    }\n    let questions = [...this.data.questions]\n    let moved_question = {...questions[this.current_pos]}\n    questions = questions.filter(q => q.order != moved_question.order)\n    questions.splice(to_index, 0, moved_question)\n    this.data.questions = questions\n    this._set_question_data_order()\n    this._build_question_from_data()\n  }\n\n  _set_question_data_order () {\n    let index = 0\n    for (let question of this.data.questions) {\n      question.order = index\n      index += 1\n    }\n  }\n}\n\n\nclass QueryCreateManager extends QueryEditBase {\n  _set_initial() {\n    this.view_type = \"create\"\n  }\n\n  show_view(on_history) {\n    this.manager.engine._hide_all_views()\n    this.manager._build_sidebar()\n    this._clean_data()\n    this.manager.engine.views.query_create.classList.remove(\"hidden\")\n    if (on_history) {\n      this.manager.engine._set_url_params(\"query-create\", null)\n    }\n  }\n\n  execute_service() {\n    fetch(this.manager.url_base, {\n      method: \"POST\",\n      body: JSON.stringify(this.data),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          if (data.uuid) {\n            this.manager.engine.cursor.key = data.uuid\n            this.manager.engine.show_view(\"query-detail\", true)\n            this._clean_data()\n          } else {\n            console.log(data)\n          }\n        })\n      } else {\n        response.json()\n        .then((data)=> {\n          this.errors = {...this.errors, ...data}\n          this._set_errors_message()\n          this.manager.engine._hide_all_views()\n          this.manager.engine.views.query_create.classList.remove(\"hidden\")\n        })\n      }\n    })\n  }\n}\n\nclass QueryUpdateManager extends QueryEditBase {\n  _set_initial() {\n    this.view_type = \"update\"\n    this._click_query_delete_modal = this._click_query_delete_modal.bind(this)\n    this._click_query_delete = this._click_query_delete.bind(this)\n    this._click_remove_question_modal = this._click_remove_question_modal.bind(this)\n    let query_delete_button = document.querySelector(\"#update-query-delete-button\")\n    query_delete_button.addEventListener(\"click\", this._click_query_delete_modal, false)\n  }\n\n  _click_query_delete_modal(event) {\n    let config = {\n      class: \"query-delete-confirmation\",\n      icon: \"alert\",\n      title: \"¿Estás seguro de que quieres eliminar esta consulta?\",\n      content: `Se perderán todas las respuestas (${this.total_responses}) y datos asociados a esta consulta de manera permanente`,\n      actions: [\n        {name: \"Sí\", click: this._click_query_delete},\n        {name: \"No\", click: this.manager.engine.hide_modal},\n      ],\n    }\n    this.manager.engine.show_modal(config)\n  }\n\n  _click_query_delete(event) {\n    this.manager.engine._set_loading()\n    this.manager.engine.hide_modal()\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"DELETE\",\n      body: JSON.stringify({\"confirmation\": \"TRUE\"}),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.manager.engine.show_view(\"query-list\", true)\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-update\", true)\n      }\n    })\n  }\n\n  _get_question_delete_callback() {\n    return this._click_remove_question_modal\n  }\n\n  _click_remove_question_modal(event) {\n    let question = event.target.closest(\".question-item\")\n    let config = {\n      class: \"query-delete-confirmation\",\n      icon: \"alert\",\n      title: \"¿Estás seguro de que quieres eliminar esta pregunta?\",\n      content: `Se perderán todas las respuestas y datos asociados a esta pregunta de manera permanente`,\n      actions: [\n        {name: \"Sí\", click: this._click_remove_question},\n        {name: \"No\", click: this.manager.engine.hide_modal},\n      ],\n      data: {question_index: question.index }\n    }\n    this.manager.engine.show_modal(config)\n  }\n\n  _click_remove_question(event) {\n    let modal_data = event.target.closest(\"#admin-modal\").data\n    let question_index = modal_data.question_index\n    this.data.questions.splice(question_index, 1)\n    this._build_question_from_data()\n    this.manager.engine.hide_modal()\n  }\n\n  show_view(on_history) {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this._set_in_view(data)\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-update\", data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine._set_url_params(\"query-list\")\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  execute_service () {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}/`, {\n      method: \"PUT\",\n      body: JSON.stringify(this.data),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          if (data.uuid) {\n            this.manager.engine.cursor.key = data.uuid\n            this.manager.engine.show_view(\"query-detail\", true)\n            this._clean_data()\n          } else {\n            console.log(data)\n          }\n        })\n      } else {\n        response.json()\n        .then((data)=> {\n          this.errors = {...this.errors, ...data}\n          this._set_errors_message()\n          this.manager.engine._hide_all_views()\n          this.manager.engine.views.query_update.classList.remove(\"hidden\")\n        })\n      }\n    })\n  }\n\n  _set_in_view (data) {\n    this.data = {\n        uuid: data.query.uuid,\n        name: data.query.name,\n        description: data.query.description,\n        start_at: data.query.start_at,\n        end_at: data.query.end_at,\n        active: data.query.active,\n        auth_email: data.query.auth_email,\n        auth_rut: data.query.auth_rut,\n        questions: [],\n    }\n    this.total_responses = data.query.total_responses\n    let questions = Array.isArray(data.query.questions)? data.query.questions: []\n    for (let question of questions) {\n      let cleaned_question = this._get_cleaned_question(question)\n      this.data.questions.push(cleaned_question)\n    }\n    for (let field in this.inputs) {\n      let input = this.inputs[field]\n      if ([\"start_at\", \"end_at\"].includes(field) && this.data[field]) {\n        input.value = new Date(this.data[field]).toISOString().split('T')[0]\n      } else {\n        input.value = this.data[field]\n      }\n    }\n    this.can_edit_questions = data.query.can_edit_questions\n    if (!this.can_edit_questions) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    }\n    this._build_question_from_data()\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_update.classList.remove(\"hidden\")\n  }\n\n  _get_cleaned_question (question) {\n    let cleaned_question = {\n      uuid: question.uuid,\n      kind: question.kind,\n      name: question.name,\n      description: question.description,\n      required: question.required,\n      order: question.order,\n    }\n    if (question.kind == \"TEXT\") {\n      cleaned_question.text_max_length = question.text_max_length\n    }\n    if (question.kind == \"SELECT\") {\n      cleaned_question.max_answers = question.max_answers\n      cleaned_question.options = question.options\n    }\n    return cleaned_question\n  }\n}\n\n\nexport {QueryCreateManager, QueryUpdateManager}\n","function get_chart (config) {\n    let id = config.id\n    let type = config.type\n    let values = config.values\n    let labels = config.labels\n    let options = config.options? config.options: {}\n    let barColors = [\n        \"#c1368c\", \"#a34895\",\"#143358\",\"#495599\",\"#54baae\"\n    ]\n    let data = {\n        labels: labels,\n        datasets: [\n            {backgroundColor: barColors, data: values, label: config.label}\n        ]\n    }\n    options.scales = {x: {ticks: {display: false}, grid: {display: false}}, y: {ticks:{display: false}}}\n    options.plugins = {\n        datalabels: {color: \"#fff\"}, legend: {display: false}, tooltip: {enabled: false}\n    }\n    options.animation = {duration: 0}\n    Chart.register(ChartDataLabels)\n    let chart = new Chart(id, {\n        type: type,\n        data: data,\n        options: options,\n    })\n    let labels_container = document.querySelector(`#${id}-labels`)\n    let color_index = 0\n    let value_index = 0\n\n    for (let label of labels) {\n        let element = document.createElement(\"div\")\n        element.classList.add(\"chart-label-container\")\n        let color_element = document.createElement(\"div\")\n        color_element.classList.add(\"chart-label-color\")\n        if (color_index >= barColors.length) {color_index = 0}\n        color_element.style.backgroundColor = barColors[color_index]\n        element.appendChild(color_element)\n        let label_value = document.createElement(\"div\")\n        label_value.classList.add(\"chart-label-value\")\n        label_value.textContent = `${values[value_index]} - ${label}`\n        element.appendChild(label_value)\n        labels_container.append(element)\n        color_index += 1\n        value_index += 1\n    }\n    labels_container.classList.remove(\"hidden\")\n    return chart\n}\n\nexport {get_chart}\n","import {\n  get_chart\n} from \"../charts.js\"\n\n\nclass QueryResultManager {\n  constructor ({manager = null, kind = null}) {\n    this.manager = manager\n    this.data = {}\n    this.kind = kind\n    this.charts = {summary: null, questions: []}\n    this._set_pre_in_view()\n    this.map = null\n    this.data_table = null\n  }\n\n  _set_pre_in_view () {\n    let tab_links = document.querySelector(`.view.query-${this.kind} .result.tab-links`)\n    let click_got_to = this.manager._click_go_to_view.bind(this.manager)\n    for (let tab_link of tab_links.children) {\n      tab_link.addEventListener(\"click\", click_got_to, false)\n    }\n    this._set_download_links()\n  }\n\n  _set_download_links () {\n    this._click_excel_link = this._click_excel_link.bind(this)\n    this._click_download_dropdown = this._click_download_dropdown.bind(this)\n    let dropdown_button = document.querySelector(`#query-${this.kind}-download-button`)\n    dropdown_button.addEventListener(\"click\", this._click_download_dropdown, false)\n    let excel_link = document.querySelector(`#query-${this.kind}-download-excel`)\n    excel_link.addEventListener(\"click\", this._click_excel_link, false)\n  }\n\n  _click_download_dropdown (event) {\n    let dropdown_content = document.querySelector(`#query-${this.kind}-dropdown`)\n    if (dropdown_content.classList.contains(\"hidden\")) {\n      dropdown_content.classList.remove(\"hidden\")\n    } else {\n      dropdown_content.classList.add(\"hidden\")\n    }\n  }\n\n  _click_excel_link (event) {\n    let excel_link = this._get_excel_link()\n    window.open(excel_link)\n    let dropdown_content = document.querySelector(`#query-${this.kind}-dropdown`)\n    dropdown_content.classList.add(\"hidden\")\n  }\n\n  _get_excel_link () {\n    return `${this.manager.url_base}${this.manager.engine.cursor.key}/excel/`\n  }\n\n  show_view(on_history) {\n    let suffix = `${[\"result\", \"questions\"].includes(this.kind)? '' : this.kind}`\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}/${suffix}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(`query-${this.kind}`, data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  _set_in_view() {\n    this.manager._build_sidebar()\n    if (this.kind == \"result\") {\n      this._set_summary()\n    } else if (this.kind == \"questions\") {\n      this._set_questions()\n    } else if (this.kind == \"map\") {\n      this._set_map()\n    } else if (this.kind == \"data\") {\n      this._set_datatables()\n    }\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views[`query_${this.kind}`].classList.remove(\"hidden\")\n  }\n\n  _set_summary () {\n    if (this.charts.summary) {\n      this.charts.summary.destroy()\n    }\n    document.querySelector(\"#query-result-summary .content\").innerHTML = \"\"\n    document.querySelector(\"#result-summary-chart-labels\").innerHTML = \"\"\n    document.querySelector(\"#result-summary-chart\").classList.add(\"hidden\")\n    document.querySelector(\n      \"#query-result .responses-total .total-value\"\n    ).textContent = this.data.total_responses\n    let summary_answer = this._get_first_select_result()\n    if (summary_answer) {\n      let answer_labels = summary_answer.options.map((x)=> x.option_name)\n      let answer_values = summary_answer.options.map((x)=> x.total)\n      let options = {indexAxis: \"x\"}\n      let chart = get_chart({\n        id: \"result-summary-chart\",\n        type: \"bar\",\n        labels: answer_labels,\n        values: answer_values,\n        options\n      })\n      document.querySelector(\"#result-summary-chart\").classList.remove(\"hidden\")\n      this.charts.summary = chart\n    }\n  }\n\n  _get_first_select_result () {\n    let result = null\n    for (let answer_result of this.data.answer_results) {\n      if (answer_result.question.kind == \"SELECT\") {\n        result = answer_result\n        break\n      }\n    }\n    return result\n  }\n\n  _set_questions() {\n    document.querySelector(\"#query-result-questions .content\").innerHTML = \"\"\n    let questions_container = document.querySelector(\"#query-result-questions\")\n    let content = questions_container.querySelector(\".content\")\n    for (let chart of this.charts.questions) {\n      chart.destroy()\n    }\n    this.charts.questions = []\n    for (let answer_result of this.data.answer_results) {\n      let template = questions_container.querySelector(\"#result-question-template\").cloneNode(true)\n      template.removeAttribute(\"id\")\n      let index = answer_result.question.index\n      template.querySelector(\".question-number .value\").textContent = index + 1\n      template.querySelector(\".question-name\").textContent = answer_result.question.name\n      template.querySelector(\".responses-total .total-value\").textContent = answer_result.total\n      content.appendChild(template)\n      if (answer_result.question.kind == \"SELECT\") {\n        let id = `result-question-chart-${index}`\n        let canvas = template.querySelector(\".question-chart\")\n        canvas.setAttribute(\"id\", id)\n        let labels = template.querySelector(\".chart-labels\")\n        labels.setAttribute(\"id\", `${id}-labels`)\n        let answer_labels = answer_result.options.map((x)=> x.option_name)\n        let answer_values = answer_result.options.map((x)=> x.total)\n        let chart = get_chart({\n          id,\n          type: \"bar\",\n          labels: answer_labels,\n          values: answer_values,\n          options: {indexAxis: \"y\"},\n        })\n        this.charts.questions.push(chart)\n        canvas.classList.remove(\"hidden\")\n        labels.classList.remove(\"hidden\")\n      }\n      template.classList.remove(\"hidden\")\n    }\n\n  }\n\n  _set_map () {\n    let map = this._get_map()\n    let question_by_uuid = {}\n    for (let question of this.data.query.questions) {\n      question_by_uuid[question.uuid] = question\n    }\n    for (let point_data of this.data.point_list) {\n      if (point_data.location) {\n        this._set_marker(map, question_by_uuid, point_data)\n      }\n    }\n\n    this._set_fetch_meta()\n  }\n\n  _get_map () {\n    if (this.map) {\n      this.map.remove()\n    }\n    document.querySelector(\"#query-result-map\").innerHTML = \"\"\n    let latlng = L.latLng(-33.447869, -70.668423)\n    let map = L.map(\"query-result-map\").setView(latlng, 9)\n    L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {\n      maxZoom: 19,\n    }).addTo(map);\n    map.attributionControl.setPrefix(\"\")\n    setTimeout(function () {\n      window.dispatchEvent(new Event('resize'));\n    }, 100);\n    this.map = map\n    return map\n  }\n\n  _set_marker(map, question_by_uuid, point_data) {\n    let marker = L.marker(\n      [point_data.location.latitude, point_data.location.longitude]\n    ).addTo(map)\n    let message = \"<div class='marker-content'>\"\n    message += this._set_html_message(\"Fecha de envío\", new Date(point_data.response.send_at).toLocaleString())\n    if (point_data.response.email) {\n      message += this._set_html_message(\"Email\", point_data.response.email)\n    }\n    if (point_data.response.rut) {\n      message += this._set_html_message(\"Rut\", point_data.response.rut)\n    }\n    message += this._get_answers_message(point_data, question_by_uuid)\n    message += '</div>'\n    marker.bindPopup(message)\n    if (this.focus == point_data.response.uuid) {\n      marker.openPopup()\n    }\n  }\n\n  _set_html_message(field, value, class_list) {\n    return `<div class=\"item ${class_list? class_list: \"\"}\"><div class=\"field\">${field}: </div><div class=\"value\">${value}</div></div>`\n  }\n\n  _get_answers_message (point_data, question_by_uuid) {\n    let message = \"<div class='responses-title'>Respuestas</div><div class='responses-list'>\"\n    for (let answer of point_data.response.answers) {\n      let question = question_by_uuid[answer.question_uuid]\n      message += this._set_html_message(`Pregunta ${question.index + 1}`, question.name)\n      if (question.kind == \"TEXT\") {\n        message += this._set_html_message(\"- Texto\", answer.text)\n      }\n      if (question.kind == \"IMAGE\") {\n        message += this._set_html_message(\"- Imagen\", `<img class=\"image\" src=\"${answer.image}\">`)\n      }\n      if (question.kind == \"SELECT\") {\n        let options = \"<div class='options-list'>\"\n        for (let option of answer.options) {\n          options += `<div class=\"option\">${option.name}</div>`\n        }\n        options += \"</div>\"\n        message += this._set_html_message(\"- Opciones\", options, \"response\")\n      }\n    }\n    message += \"</div>\"\n    return message\n  }\n\n  _set_fetch_meta () {\n    if (this.data.response_range) {\n      let start = new Date(this.data.response_range[0]).toLocaleString()\n      let end = new Date(this.data.response_range[1]).toLocaleString()\n      let range_responses = `${this.data.point_list.length} respuestas del ${start} al ${end}`\n      document.querySelector(\"#query-map .range-responses\").textContent = range_responses\n    }\n    document.querySelector(\"#query-map .fetch-at\").textContent = `Consultado en ${new Date(this.data.fetch_at).toLocaleString()}`\n  }\n\n  _set_datatables () {\n    if (this.data_table) {\n      this.data_table.destroy()\n    }\n    let dataset = []\n    for (let item of this.data.dataset) {\n      let row = this._get_row_from_item(item)\n      dataset.push(row)\n    }\n    let config = {...this.data.simpletables_config}\n    config.data.data = dataset\n    config.data.headings = this._get_datables_heading(config)\n    this.data_table = new simpleDatatables.DataTable(\"#query-result-data-table\", config)\n  }\n\n  _get_row_from_item(item) {\n    let row = []\n    for (let i = 0; i < this.data.fields.length; i++) {\n      let field = this.data.fields[i]\n      let value = item[field]\n      if (field == \"send_at\") {\n        let sat = new Date(value)\n        let month = sat.getMonth() + 1\n        month = month < 10 ? `0${month}`: month\n        let day = sat.getDate() < 10 ? `0${sat.getDate()}`: sat.getDate()\n        value = `${sat.getFullYear()}-${month}-${day} `\n        value += `${sat.getHours()}:${sat.getMinutes()}:${sat.getSeconds()}`\n      }\n      if (field == \"location\" && value) {\n        let lat = `<div class=\"latitude\"><span class=\"label\">Latitud: </span><span class=\"value\">${value.latitude}</span></div>`\n        let long = `<div class=\"latitude\"><span class=\"label\">Longitud: </span><span class=\"value\">${value.longitude}</span></div>`\n        value = `${lat}${long}`\n      }\n      if (field.includes(\"pregunta_\")) {\n        value = this._get_question_value(this.data.query.questions, field, value, item.uuid)\n      }\n      if (value == null) {\n        value = \"\"\n      }\n      row.push(value)\n    }\n    return row\n  }\n\n  _get_datables_heading(config) {\n    let headings = []\n    for (let header of config.data.headings) {\n      let description = header.desc ? `<div class=\"dt-field-desc\">${header.desc}</div>`: \"\"\n      let heading = `<div class=\"dt-field\"><div class=\"dt-field-label\">${header.label}</div>${description}</div>`\n      headings.push(heading)\n    }\n    return headings\n  }\n\n  _get_question_value(questions, field, value, response_uuid) {\n    let num = parseInt(field.match(/\\d+/)[0])\n    let index = num - 1\n    let question = questions[index]\n    let tooltip_content = `<div class=\"tooltip-title\"><b>Pregunta ${num}: </b>${question.name}</div>`\n    let final_value = value\n\n    if (question.kind == \"IMAGE\" && value) {\n      final_value = `<img class=\"tooltip-image\" src=\"${value}\">`\n      tooltip_content += `<a href=\"${value}\" target=\"_blank\">${final_value}</a>`\n    } else if (question.kind == \"POINT\" && value) {\n      let lat = `<div class=\"latitude\"><span class=\"label\">Latitud: </span><span class=\"value\">${value.latitude}</span></div>`\n      let long = `<div class=\"latitude\"><span class=\"label\">Longitud: </span><span class=\"value\">${value.longitude}</span></div>`\n      final_value = `${lat}${long}`\n      tooltip_content += `<div class=\"link-tabs\"><a class=\"link-tab\" href=\"${this.map_url}?f=${response_uuid}\">Ver en mapa</a></div>`\n    } else if (question.kind == \"SELECT\" && value) {\n      final_value = \"<ul>\"\n      for (let opt of value) {\n        final_value += `<li>${opt}</li>`\n      }\n      final_value += \"</ul>\"\n    }\n    return `${final_value}<div class=\"tooltip\">${tooltip_content}</div>`\n  }\n\n}\n\nexport {QueryResultManager}\n","class QueryShareManager {\n  constructor ({manager = null, kind = null}) {\n    this.manager = manager\n    this.data = {}\n\n  }\n  show_view(on_history) {\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this._set_in_view()\n    this.manager.engine.views.query_share.classList.remove(\"hidden\")\n    if (on_history) {\n      this.manager.engine._set_url_params(`query-share`, this.manager.engine.cursor.key)\n    }\n  }\n\n  _set_in_view() {\n    this._click_copy_link = this._click_copy_link.bind(this)\n    this._click_download_link = this._click_download_link.bind(this)\n    this._click_print_link = this._click_print_link.bind(this)\n    let copy_link = document.querySelector(\"#query-share-copy-link\")\n    copy_link.addEventListener(\"click\", this._click_copy_link, false)\n    let download_link = document.querySelector(\"#query-share-download-link\")\n    download_link.addEventListener(\"click\", this._click_download_link, false)\n    let print_link = document.querySelector(\"#query-share-print-link\")\n    print_link.addEventListener(\"click\", this._click_print_link, false)\n  }\n\n  _click_copy_link(event) {\n    let submit_link = this._get_submit_link()\n    navigator.clipboard.writeText(submit_link)\n    let action_container = event.target.closest(\".action-container\")\n    if (!action_container.querySelector(\".action-success\")) {\n      let success = document.createElement(\"div\")\n      success.classList.add(\"action-success\")\n      success.innerHTML = \"<i class='icon ok-simple'></i> Copiado correctamente\"\n      action_container.appendChild(success)\n      setTimeout(function () {\n        action_container.querySelector(\".action-success\").remove()\n      }, 3000)\n    }\n  }\n\n  _click_download_link (event) {\n    let pdf_link = this._get_pdf_link()\n    window.open(pdf_link + \"?k=download\")\n  }\n\n  _click_print_link (event) {\n    let pdf_link = this._get_pdf_link()\n    let w = window.open(pdf_link)\n    w.print()\n  }\n\n  _get_submit_link() {\n    return `https://${location.host}/submit/${this.manager.engine.cursor.key}`\n  }\n\n  _get_pdf_link () {\n    return `${this.manager.url_base}${this.manager.engine.cursor.key}/share/`\n  }\n}\n\nexport {QueryShareManager}\n","import {QueryListManager} from \"./list.js\"\nimport {QueryDetailManager} from \"./detail.js\"\nimport {QueryCreateManager, QueryUpdateManager} from \"./edit.js\"\nimport {QueryResultManager} from \"./results.js\"\nimport {QueryShareManager} from \"./share.js\"\n\n\nclass QueryManager {\n  constructor({engine = null, url_base = \"\"}) {\n    this.letters = \"ABCDEFGHIJKLMNOPQRSTUXYZ\"\n    this.engine = engine\n    this.url_base = url_base\n    this.list = new QueryListManager({manager:this})\n    this.detail = new QueryDetailManager({manager:this})\n    this.create = new QueryCreateManager({manager:this})\n    this.update = new QueryUpdateManager({manager:this})\n    this.result = new QueryResultManager({manager:this, kind: \"result\"})\n    this.questions = new QueryResultManager({manager:this, kind: \"questions\"})\n    this.map = new QueryResultManager({manager:this, kind: \"map\"})\n    this.data = new QueryResultManager({manager:this, kind: \"data\"})\n    this.share = new QueryShareManager({manager: this})\n    this._click_go_to_view = this._click_go_to_view.bind(this)\n  }\n\n  _create_query_item(item, query_item) {\n    query_item.querySelector(\".name\").textContent = item.name\n    query_item.querySelector(\".total-responses .value\").textContent = item.total_responses\n    if (!item.start_at && !item.end_at) {\n      query_item.querySelector(\".times\").classList.add(\"hidden\")\n    } else {\n      this._set_times(item, query_item)\n    }\n    let status_value = query_item.querySelector(\".status > .status-value\")\n    status_value.classList.remove(\"draft\", \"finished\", \"active\", \"earring\")\n    status_value.textContent = item.status_verbose.label\n    status_value.classList.add(item.status_verbose.code)\n    return query_item\n  }\n\n  _set_times(item, query_item) {\n    query_item.querySelector(\".times\").classList.remove(\"hidden\")\n    if (item.start_at) {\n      let start_at = new Date(item.start_at).toLocaleString().split(\",\")[0]\n      query_item.querySelector(\".start-at\").textContent = `Desde: ${start_at}`\n    }\n    if (item.end_at) {\n      let end_at = new Date(item.end_at).toLocaleString().split(\",\")[0]\n      query_item.querySelector(\".end-at\").textContent = `Hasta: ${end_at}`\n    }\n  }\n\n  _build_sidebar () {\n    let current = this.engine.cursor.focus\n    let views_with_sidebar = [\"query-detail\", \"query-update\", \"query-share\"]\n    let result_views = [\"query-result\", \"query-data\", \"query-map\", \"query-questions\"]\n    let admin_content = document.querySelector(\".admin-content\")\n    let sidebar = document.querySelector(\".admin-content > .sidebar\")\n    if (!sidebar) {\n      sidebar = document.createElement(\"div\")\n      sidebar.classList.add(\"sidebar\")\n      admin_content.prepend(sidebar)\n    } else {\n      sidebar.innerHTML = \"\"\n    }\n    if ([...result_views, ...views_with_sidebar].includes(current)) {\n      sidebar.innerHTML = `\n        <div class=\"sidebar-element${current == 'query-detail'?' current': ''}\" to=\"query-detail\">\n          Ver consulta\n        </div>\n        <div class=\"sidebar-element${result_views.includes(current)?' current': ''}\" to=\"query-result\">\n          Resultados\n        </div>\n        <div class=\"sidebar-element${current == 'query-share'?' current': ''}\" to=\"query-share\">\n          Compartir\n        </div>\n        <div class=\"sidebar-element${current == 'query-update'?' current': ''}\" to=\"query-update\">\n          Editar\n        </div>\n      `\n      for (let element of sidebar.querySelectorAll(\".sidebar-element\")) {\n        element.addEventListener(\"click\", this._click_go_to_view, false)\n      }\n    } else if (current == \"query-create\") {\n      sidebar.innerHTML = `\n        <div class=\"sidebar-element current\" to=\"query-create\">\n          Crear consulta\n        </div>\n      `\n    } else {\n      sidebar.remove()\n    }\n  }\n\n  _click_go_to_view(event) {\n    let view = event.target.getAttribute(\"to\")\n    if (view != this.engine.cursor.focus) {\n      this.engine.show_view(view, true)\n    }\n  }\n\n  get_kind_label(question_data) {\n    let kind_label = \"\"\n    if (question_data.kind === \"TEXT\" && question_data.text_max_length > 150) {\n      kind_label = \"Texto largo\"\n    } else if (question_data.kind === \"TEXT\" && question_data.text_max_length <= 150) {\n      kind_label = \"Texto corto\"\n    } else if (question_data.kind === \"SELECT\") {\n      kind_label = \"Selección múltiple\"\n    } else if (question_data.kind === \"IMAGE\") {\n      kind_label = \"Imagen\"\n    } else if (question_data.kind === \"POINT\") {\n      kind_label = \"Ubicación\"\n    }\n    return kind_label\n  }\n\n}\n\nexport {\n  QueryManager\n}\n","import {\n  QueryManager\n} from \"./queries/manager.js\"\n\n\n\nclass AdminEngine {\n  constructor (\n    { url_base = \"\" , csrf_token = \"\", focus = null, key = null, user = null}\n  ) {\n    this.user = user\n    this.csrf_token = csrf_token\n    this.cursor = {focus: focus?focus:\"query-list\", key}\n    this.url_base = url_base\n    this.ready = this.ready.bind(this)\n    this._onpopstate = this._onpopstate.bind(this)\n    document.addEventListener(\"DOMContentLoaded\", this.ready)\n    this.view_names = [\n      \"loading\",\n      \"query_list\",\n      \"query_detail\",\n      \"query_create\",\n      \"query_update\",\n      \"query_result\",\n      \"query_questions\",\n      \"query_map\",\n      \"query_data\",\n      \"query_share\",\n    ]\n    this.views = {}\n  }\n\n  ready() {\n    this.query_manager = new QueryManager({engine: this, url_base: this.url_base})\n    window.addEventListener(\"popstate\", this._onpopstate, false)\n    this._set_admin_menu()\n    this._set_views()\n    this._set_modal()\n    this.show_view(this.cursor.focus, true)\n  }\n\n  _onpopstate (event) {\n    let query_params = new URLSearchParams(window.location.search)\n    this.cursor = event.state\n    this.show_view(this.cursor.focus, false)\n  }\n\n  _click_menu_item(event) {\n    let focus = event.target.focus\n    this.show_view(focus, true)\n    event.target.closest(\".menu-content\").classList.add(\"hidden\")\n  }\n\n  _set_admin_menu() {\n    this._click_menu_item = this._click_menu_item.bind(this)\n    let menu_button = document.querySelector(\"#navbar .menu-dropdown .menu-button\")\n    let menu_content = document.querySelector(\"#navbar .menu-dropdown .menu-content\")\n    menu_button.addEventListener(\"click\", (event) => {\n      if (menu_content.classList.contains(\"hidden\")) {\n        menu_content.classList.remove(\"hidden\")\n      } else {\n        menu_content.classList.add(\"hidden\")\n      }\n    })\n    this._set_admin_menu_item(\"query-create-link\", \"query-create\", menu_content)\n    this._set_admin_menu_item(\"query-list-link\", \"query-list\", menu_content)\n  }\n\n  _set_admin_menu_item(id, focus, menu_content) {\n    let menu_item = menu_content.querySelector(`#${id}`)\n    menu_item.focus = focus\n    for (let child of menu_item.children) {\n      child.focus = focus\n    }\n    menu_item.addEventListener(\"click\", this._click_menu_item, false)\n  }\n\n  _set_views () {\n    for (let name of this.view_names) {\n      let view = document.querySelector(`#${name.replace(\"_\", \"-\")}`)\n      this.views[name] = view\n    }\n  }\n\n  _set_modal() {\n    this._click_out_modal_content = this._click_out_modal_content.bind(this)\n    let modal = document.querySelector(\"#admin-modal\")\n    modal.addEventListener(\"click\", this._click_out_modal_content, false)\n  }\n\n  _click_out_modal_content(event) {\n    if (event.target.getAttribute(\"id\") === \"admin-modal\") {\n      this.hide_modal()\n    }\n  }\n\n  _hide_all_views () {\n    for (let name in this.views) {\n      this.views[name].classList.add(\"hidden\")\n    }\n  }\n\n  _set_loading () {\n    this._hide_all_views()\n    this.views.loading.classList.remove(\"hidden\")\n  }\n\n  show_view(name, on_history) {\n    this._set_loading()\n    this.cursor.focus = name\n    let view_name = name.split(\"-\")\n    let view_kind = view_name[0]\n    let view_selector = view_name[1]\n    let manager = null\n    if (view_kind == \"query\") {\n      manager = this.query_manager[view_selector]\n    }\n    if (manager && manager.show_view) {\n      manager.show_view(on_history)\n    } else {\n      this.cursor.focus = \"query-list\"\n      this.query_manager.list.show_view(on_history)\n    }\n  }\n\n  _set_url_params(focus, key) {\n    let query_params = new URLSearchParams(window.location.search)\n    query_params.set(\"f\", focus)\n    this.cursor.focus = focus\n    if (key) {\n      query_params.set(\"k\", key)\n      this.cursor.key = key\n    } else {\n      query_params.delete(\"k\")\n      this.cursor.key = null\n    }\n    history.pushState(this.cursor, null, \"?\" + query_params.toString())\n  }\n\n  show_modal(config) {\n    let modal = document.querySelector(\"#admin-modal\")\n    let html_element = document.createElement(\"div\")\n    html_element.classList.add(config.class)\n    html_element.innerHTML = `\n      <div class=\"modal-icon-${config.icon}\"></div>\n      <div class=\"modal-title\">${config.title}</div>\n      <div class=\"modal-content\">${config.content}</div>\n      <div class=\"modal-actions\"></div>\n    `\n    modal.data = config.data\n    let actions = html_element.querySelector(\".modal-actions\")\n    for (let action of config.actions) {\n      let button = document.createElement(\"div\")\n      button.classList.add(\"primary-button\")\n      button.innerText = action.name\n      button.addEventListener(\"click\", action.click, false)\n      actions.appendChild(button)\n    }\n    modal.querySelector(\".admin-modal-content\").appendChild(html_element)\n    modal.classList.remove(\"hidden\")\n  }\n\n  hide_modal() {\n    let modal = document.querySelector(\"#admin-modal\")\n    modal.classList.add(\"hidden\")\n    modal.querySelector(\".admin-modal-content\").innerHTML = \"\"\n  }\n}\n\nexport {AdminEngine}\n"],"names":["focus_names","entry","identifier","detail","question","suffixes","cont","button_names","start","back","submit","_get_question_input_list","containers","question_list","i","length","question_inputs","querySelectorAll","input","question_index","push","Array","from","get_components","document","getEleme